import React, {
  forwardRef,
  useCallback,
  useEffect,
  useMemo,
  useState,
  type ComponentProps,
} from 'react';
import type { DropdownMenuItemProps, DropdownMenuItemValue } from '../../../types/ui';
import { Size, IconSize } from '../../../types/sizes';
import { Icon } from '../Icon/Icon';
import { Dropdown } from '../Dropdown/Dropdown';
import {
  CalendarRoot,
  CalendarTitle,
  CalendarToolbar,
  CalendarMonthDropdownWrap,
  CalendarMonthTrigger,
  CalendarMonthTriggerLabel,
  CalendarReadonlyMonth,
  CalendarChevronFlip,
  CalendarNavGroup,
  CalendarNavButton,
  CalendarWeekdays,
  CalendarWeekdayCell,
  CalendarGrid,
  CalendarDayButton,
  CalendarFooter,
} from './Calendar.style';
import {
  addMonths,
  buildCalendarGrid,
  buildMonthYearOptions,
  clampVisibleMonthStart,
  getRangeDayVisualFlags,
  getWeekdayLabels,
  isDateOutsideMinMax,
  isSameCalendarDay,
  monthYearKey,
  parseMonthYearKey,
  startOfMonth,
} from './handlers';
import type { CalendarProps } from '../../../types/ui';
import { DateRollerPicker } from '../DateRollerPicker/DateRollerPicker';
import { CalendarMonthYearSplit } from './CalendarMonthYearSplit';

/**
 * Календарь по макету: сетка месяца, навигация, выбор дня, выпадающий список месяца/года.
 * @param props - Пропсы календаря.
 * @param ref - Ref на корневой контейнер.
 */
export const Calendar = forwardRef<HTMLDivElement, CalendarProps>(
  (
    {
      value: valueProp,
      defaultValue = null,
      defaultVisibleMonth,
      visibleMonth: visibleMonthProp,
      onChange,
      onVisibleMonthChange,
      locale = 'ru-RU',
      minDate,
      maxDate,
      isDateDisabled,
      showTitle = false,
      weekStartsOn = 1,
      headerMode = 'monthYear',
      showMonthPicker = true,
      monthPickerRange = 36,
      size = Size.MD,
      disabled = false,
      selectionMode = 'single',
      rangeStart = null,
      rangeEnd = null,
      rangeHoverDate = null,
      onSelectDate,
      weekdays: weekdaysProp,
      footer,
      embedded = false,
      fullWidth = false,
      onDayMouseEnter,
      onDayMouseLeave,
      showDateRollers = false,
      monthYearLayout = 'combined',
      onRollersDateChange,
      className,
      ...rest
    },
    ref,
  ) => {
    const isControlled = valueProp !== undefined;
    const [internalValue, setInternalValue] = useState<Date | null>(defaultValue ?? null);
    const selected = isControlled ? (valueProp ?? null) : internalValue;

    const isVisibleControlled = visibleMonthProp !== undefined;
    const [internalVisible, setInternalVisible] = useState<Date>(() =>
      clampVisibleMonthStart(
        startOfMonth(visibleMonthProp ?? defaultVisibleMonth ?? selected ?? new Date()),
        minDate,
        maxDate,
      ),
    );

    const effectiveVisible = useMemo(() => {
      const base = isVisibleControlled ? visibleMonthProp! : internalVisible;
      return clampVisibleMonthStart(startOfMonth(base), minDate, maxDate);
    }, [isVisibleControlled, visibleMonthProp, internalVisible, minDate, maxDate]);

    useEffect(() => {
      if (!isVisibleControlled && isControlled && valueProp) {
        setInternalVisible(clampVisibleMonthStart(startOfMonth(valueProp), minDate, maxDate));
      }
    }, [isVisibleControlled, isControlled, valueProp, minDate, maxDate]);

    const setVisibleMonth = useCallback(
      (next: Date) => {
        const clamped = clampVisibleMonthStart(startOfMonth(next), minDate, maxDate);
        if (!isVisibleControlled) {
          setInternalVisible(clamped);
        }
        onVisibleMonthChange?.(clamped);
      },
      [isVisibleControlled, minDate, maxDate, onVisibleMonthChange],
    );

    const [monthMenuOpen, setMonthMenuOpen] = useState(false);

    const weekdayLabels = useMemo(() => {
      if (weekdaysProp?.length === 7) {
        return weekdaysProp;
      }
      return getWeekdayLabels(locale, weekStartsOn);
    }, [weekdaysProp, locale, weekStartsOn]);

    const cells = useMemo(
      () => buildCalendarGrid(effectiveVisible, weekStartsOn),
      [effectiveVisible, weekStartsOn],
    );

    const monthItems: DropdownMenuItemProps[] = useMemo(
      () =>
        buildMonthYearOptions(
          effectiveVisible,
          monthPickerRange,
          monthPickerRange,
          locale,
          minDate,
          maxDate,
        ).map((o) => ({ label: o.label, value: o.value })),
      [effectiveVisible, monthPickerRange, locale, minDate, maxDate],
    );

    const triggerLabel = useMemo(() => {
      const refDate =
        headerMode === 'monthYear' ? effectiveVisible : (selected ?? effectiveVisible);
      if (headerMode === 'full') {
        return new Intl.DateTimeFormat(locale, {
          day: 'numeric',
          month: 'long',
          year: 'numeric',
        }).format(refDate);
      }
      if (headerMode === 'dayMonth') {
        return new Intl.DateTimeFormat(locale, {
          day: 'numeric',
          month: 'long',
        }).format(refDate);
      }
      return new Intl.DateTimeFormat(locale, { month: 'long', year: 'numeric' }).format(
        effectiveVisible,
      );
    }, [headerMode, effectiveVisible, selected, locale]);

    const dropdownValue = monthYearKey(effectiveVisible);

    const handleMonthSelect = useCallback(
      (v: DropdownMenuItemValue | undefined) => {
        if (v == null || typeof v !== 'string') {
          return;
        }
        const parsed = parseMonthYearKey(v);
        if (parsed) {
          setVisibleMonth(parsed);
        }
      },
      [setVisibleMonth],
    );

    const goPrevMonth = useCallback(() => {
      setVisibleMonth(addMonths(effectiveVisible, -1));
    }, [effectiveVisible, setVisibleMonth]);

    const goNextMonth = useCallback(() => {
      setVisibleMonth(addMonths(effectiveVisible, 1));
    }, [effectiveVisible, setVisibleMonth]);

    const prevNavDisabled = useMemo(() => {
      if (!minDate) {
        return false;
      }
      const prev = addMonths(effectiveVisible, -1);
      return startOfMonth(prev).getTime() < startOfMonth(minDate).getTime();
    }, [effectiveVisible, minDate]);

    const nextNavDisabled = useMemo(() => {
      if (!maxDate) {
        return false;
      }
      const nxt = addMonths(effectiveVisible, 1);
      return startOfMonth(nxt).getTime() > startOfMonth(maxDate).getTime();
    }, [effectiveVisible, maxDate]);

    const handleDayClick = useCallback(
      (d: Date) => {
        if (disabled) {
          return;
        }
        const dayOnly = new Date(d.getFullYear(), d.getMonth(), d.getDate());
        if (isDateOutsideMinMax(dayOnly, minDate, maxDate)) {
          return;
        }
        if (isDateDisabled?.(dayOnly)) {
          return;
        }
        if (onSelectDate) {
          onSelectDate(dayOnly);
          return;
        }
        if (!isControlled) {
          setInternalValue(dayOnly);
        }
        onChange?.(dayOnly);
      },
      [disabled, minDate, maxDate, isDateDisabled, onSelectDate, isControlled, onChange],
    );

    const rollerValue = useMemo(() => {
      if (selectionMode === 'range') {
        const anchor = rangeEnd ?? rangeStart;
        if (anchor) {
          return new Date(anchor.getFullYear(), anchor.getMonth(), anchor.getDate());
        }
        return new Date(effectiveVisible.getFullYear(), effectiveVisible.getMonth(), 1);
      }
      if (selected) {
        return new Date(selected.getFullYear(), selected.getMonth(), selected.getDate());
      }
      return new Date(effectiveVisible.getFullYear(), effectiveVisible.getMonth(), 1);
    }, [selectionMode, rangeEnd, rangeStart, selected, effectiveVisible]);

    const handleRollersChange = useCallback(
      (next: Date) => {
        const dayOnly = new Date(next.getFullYear(), next.getMonth(), next.getDate());
        if (disabled) {
          return;
        }
        if (isDateOutsideMinMax(dayOnly, minDate, maxDate)) {
          return;
        }
        if (isDateDisabled?.(dayOnly)) {
          return;
        }
        setVisibleMonth(startOfMonth(dayOnly));
        if (onRollersDateChange) {
          onRollersDateChange(dayOnly);
          return;
        }
        handleDayClick(next);
      },
      [
        disabled,
        minDate,
        maxDate,
        isDateDisabled,
        onRollersDateChange,
        setVisibleMonth,
        handleDayClick,
      ],
    );

    const today = useMemo(() => new Date(), []);

    const calendarRootProps: ComponentProps<typeof CalendarRoot> = {
      ref,
      ...rest,
      className,
      $size: size,
      $embedded: embedded,
      $fullWidth: fullWidth,
      role: 'group',
      'aria-label': 'Календарь',
    };

    return (
      <CalendarRoot {...calendarRootProps}>
        {showTitle ? <CalendarTitle $size={size}>Календарь</CalendarTitle> : null}
        {showMonthPicker && monthYearLayout === 'split' ? (
          <CalendarMonthYearSplit
            visibleMonth={effectiveVisible}
            onVisibleMonthChange={setVisibleMonth}
            locale={locale}
            onPrevMonth={goPrevMonth}
            onNextMonth={goNextMonth}
            prevNavDisabled={prevNavDisabled}
            nextNavDisabled={nextNavDisabled}
            minDate={minDate}
            maxDate={maxDate}
            disabled={disabled}
          />
        ) : (
          <CalendarToolbar>
            {showMonthPicker ? (
              <CalendarMonthDropdownWrap>
                <Dropdown
                  trigger={
                    <CalendarMonthTrigger
                      type="button"
                      $open={monthMenuOpen}
                      disabled={disabled}
                      aria-haspopup="listbox"
                      aria-expanded={monthMenuOpen}
                    >
                      <CalendarMonthTriggerLabel>{triggerLabel}</CalendarMonthTriggerLabel>
                      <CalendarChevronFlip $open={monthMenuOpen} aria-hidden>
                        <Icon
                          name="IconPlainerChevronDown"
                          size={IconSize.MD}
                          color="currentColor"
                        />
                      </CalendarChevronFlip>
                    </CalendarMonthTrigger>
                  }
                  items={monthItems}
                  value={dropdownValue}
                  onSelect={handleMonthSelect}
                  disabled={disabled}
                  size={Size.SM}
                  menuDensity="compact"
                  searchable={false}
                  menuMaxHeight={240}
                  isMenuOpen={monthMenuOpen}
                  onMenuOpenChange={setMonthMenuOpen}
                  disableAutoFocus
                  positioningMode="autoFlip"
                />
              </CalendarMonthDropdownWrap>
            ) : (
              <CalendarReadonlyMonth>{triggerLabel}</CalendarReadonlyMonth>
            )}
            <CalendarNavGroup>
              <CalendarNavButton
                type="button"
                aria-label="Предыдущий месяц"
                $disabled={disabled || prevNavDisabled}
                disabled={disabled || prevNavDisabled}
                onClick={goPrevMonth}
              >
                <Icon name="IconPlainerArrowLeft" size={IconSize.SM} color="currentColor" />
              </CalendarNavButton>
              <CalendarNavButton
                type="button"
                aria-label="Следующий месяц"
                $disabled={disabled || nextNavDisabled}
                disabled={disabled || nextNavDisabled}
                onClick={goNextMonth}
              >
                <Icon name="IconPlainerArrowRight" size={IconSize.SM} color="currentColor" />
              </CalendarNavButton>
            </CalendarNavGroup>
          </CalendarToolbar>
        )}

        {showDateRollers ? (
          <DateRollerPicker
            value={rollerValue}
            onChange={handleRollersChange}
            locale={locale}
            minDate={minDate}
            maxDate={maxDate}
            isDateDisabled={isDateDisabled}
            size={size}
            disabled={disabled}
          />
        ) : null}

        <CalendarWeekdays $size={size} $fullWidth={fullWidth}>
          {weekdayLabels.map((wd, i) => (
            <CalendarWeekdayCell key={`${wd}-${i}`}>{wd}</CalendarWeekdayCell>
          ))}
        </CalendarWeekdays>

        <CalendarGrid $size={size} $fullWidth={fullWidth}>
          {cells.map((cell, idx) => {
            const dayOnly = new Date(
              cell.date.getFullYear(),
              cell.date.getMonth(),
              cell.date.getDate(),
            );
            const outside = isDateOutsideMinMax(dayOnly, minDate, maxDate);
            const customDis = isDateDisabled?.(dayOnly) ?? false;
            const isDis = disabled || outside || customDis;
            const isSel =
              selectionMode === 'single' &&
              selected != null &&
              isSameCalendarDay(dayOnly, selected);
            const rangeFlags = getRangeDayVisualFlags(
              dayOnly,
              selectionMode,
              rangeStart,
              rangeEnd,
              rangeHoverDate,
            );
            const isTod = isSameCalendarDay(dayOnly, today);

            return (
              <CalendarDayButton
                key={idx}
                type="button"
                $size={size}
                $fullWidth={fullWidth}
                $inCurrentMonth={cell.inCurrentMonth}
                $selected={Boolean(isSel)}
                $inRange={rangeFlags.inRange}
                $rangeStart={rangeFlags.rangeStart}
                $rangeEnd={rangeFlags.rangeEnd}
                $today={isTod}
                $disabled={isDis}
                disabled={isDis}
                onClick={() => handleDayClick(cell.date)}
                onMouseEnter={() => onDayMouseEnter?.(dayOnly)}
                onMouseLeave={() => onDayMouseLeave?.()}
              >
                {cell.date.getDate()}
              </CalendarDayButton>
            );
          })}
        </CalendarGrid>

        {footer ? <CalendarFooter>{footer}</CalendarFooter> : null}
      </CalendarRoot>
    );
  },
);

Calendar.displayName = 'Calendar';

import styled, { css } from 'styled-components';
import { motion } from 'framer-motion';
import type { CardProps } from '../../../types/ui';
import { CardVariant } from '../../../types/ui';
import { Size } from '../../../types/sizes';
import type { ThemeType } from '../../../types/theme';

/**
 * Нормализует входной размер карточки к ключам темы (`XS | SM | MD | LG | XL`).
 * Поддерживает как enum-значения, так и строковые варианты в нижнем регистре из сторис.
 * @param rawSize - входящее значение `size`/`padding` из пропсов карточки
 */
const resolveCardSizeKey = (rawSize: CardProps['size'] | CardProps['padding']): Size => {
  if (typeof rawSize !== 'string' || rawSize.length === 0) {
    return Size.MD;
  }

  const normalizedSize = rawSize.toUpperCase() as keyof typeof Size;
  return Size[normalizedSize] ?? Size.MD;
};

/**
 * Возвращает настройки размера карточки с безопасным fallback на `MD`.
 * @param theme - активная тема styled-components
 * @param rawSize - входящее значение `size`/`padding` из пропсов карточки
 */
const getCardSizeSettings = (
  theme: ThemeType,
  rawSize: CardProps['size'] | CardProps['padding'],
): ThemeType['cards']['sizes'][Size] => {
  const resolvedSize = resolveCardSizeKey(rawSize);
  return theme.cards?.sizes?.[resolvedSize] ?? theme.cards.sizes[Size.MD];
};

/**
 * Стилизованная карточка
 * @param variant - вариант карточки (ELEVATED, OUTLINED, FILLED)
 * @param size - размер карточки
 * @param padding - внутренние отступы
 * @param hoverable - возможность наведения
 * @param clickable - возможность клика
 * @param fullWidth - полная ширина
 */
export const StyledCard = styled(motion.div)<CardProps>`
  background: ${({ theme }) => theme.cards.variants.elevated.background};
  color: ${({ theme }) => theme.cards.variants.elevated.color};
  border-radius: ${({ theme, size = Size.MD }) => getCardSizeSettings(theme, size).borderRadius};
  overflow: ${({ theme }) => theme.cards.settings.overflow};
  transition: ${({ theme }) => theme.cards.animations.transition};
  user-select: ${({ theme }) => theme.cards.settings.userSelect};

  ${({ fullWidth, theme }) =>
    fullWidth &&
    css`
      width: ${theme.cards.settings.fullWidth};
    `}

  ${({ variant = CardVariant.ELEVATED, theme }) => {
    switch (variant) {
      case CardVariant.ELEVATED:
        return css`
          background: ${theme.cards.variants.elevated.background};
          color: ${theme.cards.variants.elevated.color};
          box-shadow: ${theme.boxShadow?.md || theme.cards.variants.elevated.boxShadow};
          border: ${theme.cards.variants.elevated.border || 'none'};
        `;
      case CardVariant.OUTLINED:
        return css`
          background: ${theme.cards.variants.outlined.background};
          color: ${theme.cards.variants.outlined.color};
          border: ${theme.cards.variants.outlined.border};
          box-shadow: ${theme.cards.variants.outlined.boxShadow || 'none'};
        `;
      case CardVariant.FILLED:
        return css`
          background: ${theme.cards.variants.filled.background};
          color: ${theme.cards.variants.filled.color};
          box-shadow: ${theme.cards.variants.filled.boxShadow || 'none'};
          border: ${theme.cards.variants.filled.border || 'none'};
        `;
      default:
        return css`
          background: ${theme.cards.variants.elevated.background};
          color: ${theme.cards.variants.elevated.color};
          box-shadow: ${theme.boxShadow?.md || theme.cards.variants.elevated.boxShadow};
          border: ${theme.cards.variants.elevated.border || 'none'};
        `;
    }
  }}

  ${({ theme, size = Size.MD }) => css`
    min-height: ${getCardSizeSettings(theme, size).minHeight};
  `}

  ${({ theme, padding = Size.MD }) => css`
    padding: ${getCardSizeSettings(theme, padding).padding};
  `}

  ${({ hoverable, clickable, theme, variant = CardVariant.ELEVATED }) =>
    (hoverable || clickable) &&
    css`
      cursor: ${theme.cards.settings.cursor.clickable};
      &:hover {
        transform: ${theme.cards.states.hover.transform};
        ${variant === CardVariant.ELEVATED &&
        css`
          box-shadow: ${theme.cards.states.hover.boxShadow.elevated};
        `}
        ${variant === CardVariant.OUTLINED &&
        css`
          box-shadow: ${theme.cards.states.hover.boxShadow.outlined};
        `}
        ${variant === CardVariant.FILLED &&
        css`
          box-shadow: ${theme.cards.states.hover.boxShadow.filled};
        `}
      }
      &:active {
        transform: ${theme.cards.states.active.transform};
      }
    `}
`;

/**
 * Заголовок карточки
 */
export const CardHeader = styled.div`
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-bottom: ${({ theme }) => theme.cards.components.header.marginBottom};
  padding-bottom: ${({ theme }) => theme.cards.components.header.paddingBottom};
  ${({ theme }) =>
    theme.cards.components.header.borderBottom &&
    `border-bottom: ${theme.cards.components.header.borderBottom};`}
`;

/**
 * Заголовок карточки
 */
export const CardTitle = styled.h3`
  font-family: ${({ theme }) => theme.cards.components.title.fontFamily};
  font-size: ${({ theme }) => theme.cards.components.title.fontSize};
  font-weight: ${({ theme }) => theme.cards.components.title.fontWeight};
  line-height: ${({ theme }) => theme.cards.components.title.lineHeight};
  color: ${({ theme }) => theme.cards.components.title.color};
  margin: ${({ theme }) => theme.cards.components.title.margin};
`;

/**
 * Подзаголовок карточки
 */
export const CardSubtitle = styled.p`
  font-family: ${({ theme }) => theme.cards.components.subtitle.fontFamily};
  font-size: ${({ theme }) => theme.cards.components.subtitle.fontSize};
  font-weight: ${({ theme }) => theme.cards.components.subtitle.fontWeight};
  line-height: ${({ theme }) => theme.cards.components.subtitle.lineHeight};
  color: ${({ theme }) => theme.cards.components.subtitle.color};
  margin: ${({ theme }) => theme.cards.components.subtitle.margin};
`;

/**
 * Контент карточки
 */
export const CardContent = styled.div`
  flex: 1;
  font-family: ${({ theme }) => theme.cards.components.content.fontFamily};
  font-size: ${({ theme }) => theme.cards.components.content.fontSize};
  font-weight: ${({ theme }) => theme.cards.components.content.fontWeight};
  line-height: ${({ theme }) => theme.cards.components.content.lineHeight};
  color: ${({ theme }) => theme.cards.components.content.color};
`;

/**
 * Футер карточки
 */
export const CardFooter = styled.div`
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-top: ${({ theme }) => theme.cards.components.footer.marginTop};
  padding-top: ${({ theme }) => theme.cards.components.footer.paddingTop};
  ${({ theme }) =>
    theme.cards.components.footer.borderTop &&
    `border-top: ${theme.cards.components.footer.borderTop};`}
`;

/**
 * Действия карточки
 */
export const CardActions = styled.div`
  display: flex;
  gap: ${({ theme }) => theme.cards.components.actions.gap};
  align-items: center;
`;

import React from 'react';
import { clsx } from 'clsx';
import type { DividerProps } from '../../../types/ui';
import { DividerOrientation } from '../../../types/ui';
import { Size } from '../../../types/sizes';
import { DividerContainer } from './Divider.style';

export const Divider: React.FC<DividerProps> = ({
  orientation = DividerOrientation.HORIZONTAL,
  size = Size.MD,
  className,
}) => {
  return (
    <DividerContainer
      orientation={orientation}
      size={size}
      className={clsx('ui-divider', className)}
    />
  );
};

﻿import React from 'react';
import type { Meta, StoryObj } from '@storybook/react';
import { css } from 'styled-components';
import { Dropdown } from './Dropdown';
import { DropdownDivider } from './Dropdown.style';
import { Button } from '../buttons/Button/Button';
import { ButtonVariant } from '../../../types/ui';
import type {
  DropdownMenuItemProps,
  DropdownMenuItemValue,
  DropdownProps,
} from '../../../types/ui';
import {
  applyTreeMultiSelectionToValues,
  collectTreeBranchKeysFromSections,
} from '../../../handlers/dropdownTreeSelectionHandlers';
