const meta: Meta<typeof Dropdown> = {
  title: 'UI Kit/Navigation/Dropdown',
  component: Dropdown,
  /** Чтобы в Controls отображался объект `openMenuIconProps` у сторис без своего `trigger`. */
  args: {
    openMenuIconProps: {},
  },
  parameters: {
    layout: 'padded',
    docs: {
      description: {
        component: DOC_DROPDOWN,
      },
    },
  },
  argTypes: {
