      menuWidth,
      menuMaxHeight,
      alignSelf,
      dropContainerStyle,
      dropContainerCssMixin,
      positioningMode = 'default',
      portalContainer,
      searchable = false,
      searchPlaceholder = 'Поиск...',
      searchValue,
      defaultSearchValue = '',
      onSearch,
      onSearchInputChange,
      searchFilter,
      searchFormat,
      enableKeyboardNavigation = true,
      loadItems,
      onLoadItemsError,
      renderEmptyState,
      emptyMessage = 'Нет данных',
      renderErrorState,
      inline = false,
      menuDensity = 'default',
      triggerWrapClickToggle = true,
      fullWidth = false,
      openMenuIconProps,
      defaultTriggerKind = 'button',
      tagTriggerProps,
      labelFromSelection = false,
      tagTriggerShowChevron = true,
      treeExpandable,
      treeDefaultExpanded,
      treeExpandedKeys,
      onTreeExpandedKeysChange,
      lookupTreeMenuItemByValue,
    },
    _ref,
  ) => {
    // Контролируемый или неконтролируемый режим
    const isControlled = isMenuOpen !== undefined;
    const [internalIsOpen, setInternalIsOpen] = useState(defaultOpen);
    const isOpen = isControlled ? isMenuOpen : internalIsOpen;

    const [position, setPosition] = useState({ x: 0, y: 0 });
    const [shouldRender, setShouldRender] = useState(false);
    const dropdownRef = useRef<HTMLDivElement>(null);
    const menuRef = useRef<HTMLDivElement>(null);
    /** Восстановление скролла после догрузки пунктов (элемент, который реально скроллился). */
    const scrollRestoreRef = useRef<{
      el: HTMLElement;
      prevScrollHeight: number;
      prevScrollTop: number;
    } | null>(null);
    /** Длина плоского списка при последнем вызове `onMenuLoadMore` (сброс при отходе от низа). */
    const loadMoreLastFiredAtLengthRef = useRef(-1);
    const defaultButtonTriggerRef = useRef<HTMLButtonElement | null>(null);
    const defaultTagTriggerRef = useRef<HTMLElement | null>(null);
    const isSearchControlled = searchValue !== undefined;
    const [internalSearchValue, setInternalSearchValue] = useState(defaultSearchValue ?? '');
    const [asyncItems, setAsyncItems] = useState<DropdownMenuItemProps[] | null>(null);
    const [asyncStatus, setAsyncStatus] = useState<'idle' | 'loading' | 'success' | 'error'>(
      'idle',
    );
    const [asyncError, setAsyncError] = useState<unknown>(null);
    const shouldUseAsyncItems = Boolean(loadItems) && !items;

    useEffect(() => {
      if (!searchable) return;
      if (defaultSearchValue !== undefined && !isSearchControlled) {
        setInternalSearchValue(defaultSearchValue);
      }
    }, [defaultSearchValue, isSearchControlled, searchable]);

    useEffect(() => {
      if (!searchable || isSearchControlled) return;
      if (!isOpen) {
        setInternalSearchValue(defaultSearchValue ?? '');
      }
    }, [isOpen, searchable, isSearchControlled, defaultSearchValue]);

    useEffect(() => {
      if (!shouldUseAsyncItems) {
        setAsyncItems(null);
        setAsyncStatus('idle');
        setAsyncError(null);
        return;
      }
      if (!isOpen) return;
      if (!loadItems) return;
      if (asyncStatus === 'loading') return;
      if (asyncStatus === 'success' && asyncItems && asyncItems.length > 0) return;

      let isCancelled = false;
      setAsyncStatus('loading');
      setAsyncError(null);

      loadItems()
        ?.then((result) => {
          if (isCancelled) return;
          setAsyncItems(result);
          setAsyncStatus('success');
        })
        .catch((error) => {
          if (isCancelled) return;
          setAsyncError(error);
          setAsyncStatus('error');
          onLoadItemsError?.(error);
        });

      return () => {
        isCancelled = true;
      };
    }, [shouldUseAsyncItems, isOpen, loadItems, asyncStatus, asyncItems, onLoadItemsError]);

    // Функция для изменения состояния открытия
    const handleOpenChange = React.useCallback(
      (newIsOpen: boolean) => {
        if (!isControlled) {
          setInternalIsOpen(newIsOpen);
        }
        if (newIsOpen) {
          onMenuOpened?.();
        } else {
          onMenuClosed?.();
        }
        onMenuOpenChange?.(newIsOpen);
      },
      [isControlled, onMenuOpenChange, onMenuOpened, onMenuClosed],
    );

    // Функция для вычисления позиции dropdown
    // Для position: fixed координаты должны быть относительно viewport
    const calculatePosition = React.useCallback(() => {
      return calculateDropdownPosition({
        triggerElement: targetElement || dropdownRef.current,
        menuElement: menuRef.current,
        boundaryElement: inline ? dropdownRef.current : undefined,
        mode: positioningMode,
      });
    }, [targetElement, positioningMode, inline]);

    // Закрыть меню при disabled
    useEffect(() => {
      if (disabled && isOpen) {
        handleOpenChange(false);
        setShouldRender(false);
      }
    }, [disabled, isOpen, handleOpenChange]);

    // Инициализация при defaultOpen
    useEffect(() => {
      if (defaultOpen && isOpen && !disabled) {
        const newPosition = calculatePosition();
        setPosition(newPosition);
        setShouldRender(true);
      }
    }, [defaultOpen, isOpen, disabled, calculatePosition]);

    // Закрыть dropdown при клике вне его
    useEffect(() => {
      const handleClickOutside = (event: MouseEvent) => {
        // Проверяем, был ли клик вне компонента, и вызываем обработчик onClickOutside если он передан
        const isOutside = handleClickOutsideEvent(event, dropdownRef, menuRef, onClickOutside);

        // Если клик не внутри триггера и не внутри меню, закрываем меню
        // В режиме multiSelection меню не закрывается при клике на элемент меню
        if (isOutside) {
          handleOpenChange(false);
          setShouldRender(false);
        }
      };

      if (isOpen) {
        document.addEventListener('mousedown', handleClickOutside);
        // Сначала вычисляем позицию
        const newPosition = calculatePosition();
        setPosition(newPosition);
        // Затем разрешаем рендер
        setShouldRender(true);
      } else {
        setShouldRender(false);
      }

      return () => {
        document.removeEventListener('mousedown', handleClickOutside);
      };
    }, [isOpen, calculatePosition, handleOpenChange, onClickOutside]);

    useLayoutEffect(() => {
      if (!isOpen || !shouldRender) return;
      setPosition(calculatePosition());
    }, [isOpen, shouldRender, calculatePosition]);

    useEffect(() => {
      if (!isOpen) return;
      const menu = menuRef.current;
      if (!menu || typeof ResizeObserver === 'undefined') return;

      const observer = new ResizeObserver(() => {
        setPosition(calculatePosition());
      });
      observer.observe(menu);

      return () => observer.disconnect();
    }, [isOpen, calculatePosition]);

    useEffect(() => {
      if (!isOpen || !enableKeyboardNavigation) return;
      const menu = menuRef.current;
      if (!menu) return;

      const handleKeyDown = (event: KeyboardEvent) => {
        const focusableElements = getFocusableElements(menu);
        if (!focusableElements.length) return;

        const currentIndex = getFocusableElementIndex(focusableElements, document.activeElement);
        const lastIndex = focusableElements.length - 1;

        const focusByIndex = (index: number) => {
          event.preventDefault();
          focusableElements[index]?.focus();
        };

        switch (event.key) {
          case 'ArrowDown':
            focusByIndex((currentIndex + 1) % focusableElements.length);
            break;
          case 'ArrowUp':
            focusByIndex((currentIndex - 1 + focusableElements.length) % focusableElements.length);
            break;
          case 'Home':
            focusByIndex(0);
            break;
          case 'End':
            focusByIndex(lastIndex);
            break;
          case 'Tab':
            focusByIndex(
              event.shiftKey
                ? (currentIndex - 1 + focusableElements.length) % focusableElements.length
                : (currentIndex + 1) % focusableElements.length,
            );
            break;
          default:
            break;
        }
      };

      menu.addEventListener('keydown', handleKeyDown);
      return () => menu.removeEventListener('keydown', handleKeyDown);
    }, [isOpen, enableKeyboardNavigation]);

    // Закрыть dropdown при нажатии Escape
    useEffect(() => {
      const handleEscape = (event: KeyboardEvent) => {
        if (event.key === 'Escape') {
          handleOpenChange(false);
        }
      };

      if (isOpen) {
        document.addEventListener('keydown', handleEscape);
      }

      return () => {
        document.removeEventListener('keydown', handleEscape);
      };
    }, [isOpen, handleOpenChange]);

    // Обновляем позицию при изменении targetElement
    useEffect(() => {
      if (isOpen) {
        setPosition(calculatePosition());
      }
    }, [targetElement, isOpen, calculatePosition]);

    // Обновляем позицию при изменении размера окна
    useEffect(() => {
      const handleResize = () => {
        if (isOpen) {
          setPosition(calculatePosition());
        }
      };

      window.addEventListener('resize', handleResize);
      return () => window.removeEventListener('resize', handleResize);
    }, [isOpen, calculatePosition]);

    // Обновляем позицию при скролле страницы
    useEffect(() => {
      if (!isOpen) return;

      const handleScroll = () => {
        // Используем flushSync для синхронного обновления позиции без задержки
        flushSync(() => {
          setPosition(calculatePosition());
        });
      };

      window.addEventListener('scroll', handleScroll, true);
      document.addEventListener('scroll', handleScroll, true);

      const scrollableElements = findScrollableParents(dropdownRef.current);
      scrollableElements.forEach((element) => {
        if (element instanceof HTMLElement) {
          element.addEventListener('scroll', handleScroll, true);
        }
      });

      return () => {
        window.removeEventListener('scroll', handleScroll, true);
        document.removeEventListener('scroll', handleScroll, true);
        removeScrollListeners(scrollableElements, handleScroll);
      };
    }, [isOpen, calculatePosition]);

    // Автоматически фокусируем стандартный триггер при монтировании
    useEffect(() => {
      if (disableAutoFocus || disabled || skeleton) return;
      if (trigger) return;

      const element =
        defaultTriggerKind === 'tag'
          ? defaultTagTriggerRef.current
          : defaultButtonTriggerRef.current;
      if (!element) return;

      const rect = element.getBoundingClientRect();
      const isHorizontallyVisible = rect.left >= 0 && rect.left <= window.innerWidth;
      const isVerticallyVisible = rect.top >= 0 && rect.bottom <= window.innerHeight;

      if (!isHorizontallyVisible || !isVerticallyVisible) {
        return;
      }

      element.focus();
    }, [disableAutoFocus, disabled, skeleton, trigger, defaultTriggerKind]);

    const currentSearchValue = searchable
      ? isSearchControlled
        ? (searchValue ?? '')
        : internalSearchValue
      : '';

    const handleSearchChange = React.useCallback(
      (value: string) => {
        if (!isSearchControlled) {
          setInternalSearchValue(value);
        }
        onSearch?.(value, searchFormat);
      },
      [isSearchControlled, onSearch, searchFormat],
    );

    const handleRetryLoadItems = React.useCallback(() => {
      if (!shouldUseAsyncItems) return;
      setAsyncItems(null);
      setAsyncStatus('idle');
      setAsyncError(null);
    }, [shouldUseAsyncItems]);

    const handleTriggerClick = () => {
      if (disabled) return;
      handleOpenChange(!isOpen);
    };

    const handleItemSelect = React.useCallback(
      (value?: DropdownMenuItemValue, event?: React.MouseEvent<HTMLElement>) => {
        // В режиме multiSelection меню не закрывается при выборе
        if (!multiSelection) {
          handleOpenChange(false);
          setShouldRender(false);
        }
        if (onSelect) {
          onSelect(value, event);
        }
      },
      [onSelect, handleOpenChange, multiSelection],
    );

    // В режиме multiSelection value должен быть массивом
    const normalizedValue = React.useMemo(
      () => normalizeDropdownValue(value, multiSelection),
      [multiSelection, value],
    );

    const normalizedSearchQuery = currentSearchValue.trim().toLowerCase();

    /** Список из `<DropdownMenuFromDefinitions definitions={...} />` — тот же источник, что и `items`, для поиска и догрузки. */
    const definitionsFromMenuChild = React.useMemo(() => {
      const nodes = React.Children.toArray(children);
      for (const node of nodes) {
        if (
          React.isValidElement(node) &&
          (node.type as React.ComponentType) === DropdownMenuFromDefinitions
        ) {
          return (node.props as DropdownMenuFromDefinitionsProps).definitions;
        }
      }
      return undefined;
    }, [children]);

    /** Откуда берётся список: проп `items` / `asyncItems` или дочерний `DropdownMenuFromDefinitions`. */
    const itemListSourceKind = React.useMemo<'props' | 'child' | 'none'>(() => {
      if (items) {
        return 'props';
      }
      if (asyncItems) {
        return 'props';
      }
      if (definitionsFromMenuChild !== undefined) {
        return 'child';
      }
      return 'none';
    }, [items, asyncItems, definitionsFromMenuChild]);

    const resolvedDefinitions = React.useMemo<
      (DropdownMenuItemProps | DropdownMenuGroup)[] | null
    >(() => {
      if (items) {
        return items;
      }
      if (asyncItems) {
        return [...asyncItems];
      }
      if (definitionsFromMenuChild !== undefined) {
        return definitionsFromMenuChild;
      }
      return null;
    }, [items, asyncItems, definitionsFromMenuChild]);

    const doesItemMatchSearch = React.useCallback(
      (item: DropdownMenuItemProps) => {
        if (!searchable || !normalizedSearchQuery) return true;
        if (searchFilter) {
          return searchFilter(currentSearchValue, item);
        }
        const parts = getDropdownItemSearchHaystackParts(item);
        return defaultDropdownSearchMatches(currentSearchValue, searchFormat, parts);
      },
      [searchable, normalizedSearchQuery, searchFilter, currentSearchValue, searchFormat],
    );

    const filteredDefinitions = React.useMemo(() => {
      if (!resolvedDefinitions) return null;
      if (!searchable || !normalizedSearchQuery) return resolvedDefinitions;

      const next: (DropdownMenuItemProps | DropdownMenuGroup)[] = [];
      resolvedDefinitions.forEach((definition) => {
        if (isDropdownGroup(definition)) {
          const matchedItems = definition.items.filter((item) => doesItemMatchSearch(item));
          if (matchedItems.length > 0) {
            next.push({ ...definition, items: matchedItems });
          }
        } else if (doesItemMatchSearch(definition)) {
          next.push(definition);
        }
      });
      return next;
    }, [resolvedDefinitions, searchable, normalizedSearchQuery, doesItemMatchSearch]);

    /** Скролл списка (в т.ч. вложенного при virtual scroll) + опциональная догрузка у нижней границы. */
    const handleMenuScrollCapture = React.useCallback(
      (event: React.UIEvent<HTMLDivElement>) => {
        const raw = event.target;
        if (!(raw instanceof HTMLElement)) {
          return;
        }
        if (raw.scrollHeight <= raw.clientHeight + 1) {
          return;
        }

        onMenuScroll?.({
          scrollTop: raw.scrollTop,
          scrollHeight: raw.scrollHeight,
          clientHeight: raw.clientHeight,
        });

        if (!onMenuLoadMore || menuHasMore === false || menuIsLoadingMore) {
          return;
        }

        const threshold = menuLoadMoreThresholdPx ?? 80;
        const distance = raw.scrollHeight - raw.scrollTop - raw.clientHeight;

        if (distance > threshold * 3) {
          loadMoreLastFiredAtLengthRef.current = -1;
        }
        if (distance >= threshold) {
          return;
        }

        const definitionsList = filteredDefinitions ?? resolvedDefinitions;
        if (!definitionsList?.length) {
          return;
        }
        const flat = flattenDropdownDefinitions(definitionsList);
        if (flat.length === 0) {
          return;
        }

        if (loadMoreLastFiredAtLengthRef.current === flat.length) {
          return;
        }

        const last = flat[flat.length - 1];
        const anchorValue =
          last.value !== undefined && last.value !== null ? String(last.value) : '';
        if (!anchorValue) {
          return;
        }

        loadMoreLastFiredAtLengthRef.current = flat.length;
        scrollRestoreRef.current = {
          el: raw,
          prevScrollHeight: raw.scrollHeight,
          prevScrollTop: raw.scrollTop,
        };

        void Promise.resolve(
          onMenuLoadMore({
            direction: 'end',
            anchorFlatIndex: flat.length - 1,
            anchorValue,
            anchorId: last.id,
            scrollTop: raw.scrollTop,
            scrollHeight: raw.scrollHeight,
            clientHeight: raw.clientHeight,
          }),
        ).catch(() => {
          loadMoreLastFiredAtLengthRef.current = -1;
          scrollRestoreRef.current = null;
        });
      },
      [
        onMenuScroll,
        onMenuLoadMore,
        menuHasMore,
        menuIsLoadingMore,
        menuLoadMoreThresholdPx,
        filteredDefinitions,
        resolvedDefinitions,
      ],
    );

    useLayoutEffect(() => {
      const pending = scrollRestoreRef.current;
      if (!pending?.el.isConnected) {
        scrollRestoreRef.current = null;
        return;
      }
      const { el, prevScrollHeight, prevScrollTop } = pending;
      const delta = el.scrollHeight - prevScrollHeight;
      if (delta !== 0) {
        el.scrollTop = prevScrollTop + delta;
      }
      scrollRestoreRef.current = null;
    }, [filteredDefinitions, resolvedDefinitions, items, asyncItems, definitionsFromMenuChild]);

    useEffect(() => {
      if (!isOpen) {
        loadMoreLastFiredAtLengthRef.current = -1;
        scrollRestoreRef.current = null;
      }
    }, [isOpen]);

    /** Сборка меню из `items` / `asyncItems`; при списке только из `children` рендер идёт через `cloneElement` ниже. */
    const menuBodyFromItems = React.useMemo(() => {
      if (itemListSourceKind !== 'props') {
        return null;
      }
      const sourceDefinitions = filteredDefinitions ?? resolvedDefinitions;
      if (!sourceDefinitions?.length) {
        return null;
      }
      return (
        <DropdownMenuFromDefinitions
          definitions={sourceDefinitions}
          onItemSelect={handleItemSelect}
          value={normalizedValue}
          onActivateItem={onActivateItem}
          multiSelection={multiSelection}
          showCheckbox={showCheckbox}
          disableSelectedOptionHighlight={disableSelectedOptionHighlight}
          virtualScroll={virtualScroll}
          size={size}
          menuDensity={menuDensity}
          treeExpandable={treeExpandable}
          treeDefaultExpanded={treeDefaultExpanded}
          treeExpandedKeys={treeExpandedKeys}
          onTreeExpandedKeysChange={onTreeExpandedKeysChange}
          lookupTreeMenuItemByValue={lookupTreeMenuItemByValue}
        />
      );
    }, [
      itemListSourceKind,
      filteredDefinitions,
      resolvedDefinitions,
      handleItemSelect,
      normalizedValue,
      onActivateItem,
      multiSelection,
      showCheckbox,
      disableSelectedOptionHighlight,
      virtualScroll,
      size,
      menuDensity,
      treeExpandable,
      treeDefaultExpanded,
      treeExpandedKeys,
      onTreeExpandedKeysChange,
      lookupTreeMenuItemByValue,
    ]);

    const injectDropdownMenuShellProps = React.useCallback(
      (
        child: React.ReactElement<DropdownMenuProps | DropdownMenuFromDefinitionsProps>,
      ): React.ReactElement => {
        const isFromDefinitionsMenu =
          (child.type as React.ComponentType) === DropdownMenuFromDefinitions;
        return React.cloneElement(child, {
          onItemSelect: handleItemSelect,
          value: normalizedValue,
          onActivateItem,
          multiSelection,
          showCheckbox,
          disableSelectedOptionHighlight,
          virtualScroll,
          size,
          menuDensity,
          treeExpandable,
          ...(isFromDefinitionsMenu ? { treeDefaultExpanded } : {}),
          treeExpandedKeys,
          onTreeExpandedKeysChange,
          lookupTreeMenuItemByValue,
        } as Record<string, unknown>);
      },
      [
        handleItemSelect,
        normalizedValue,
        onActivateItem,
        multiSelection,
        showCheckbox,
        disableSelectedOptionHighlight,
        virtualScroll,
        size,
        menuDensity,
        treeExpandable,
        treeDefaultExpanded,
        treeExpandedKeys,
        onTreeExpandedKeysChange,
        lookupTreeMenuItemByValue,
      ],
    );

    const renderChildren = React.useMemo(() => {
      if (menuBodyFromItems) {
        return menuBodyFromItems;
      }
      if (!children) {
        return null;
      }
      return React.Children.map(children as React.ReactNode, (child) => {
        if (!React.isValidElement(child)) {
          return child;
        }

        if ((child.type as React.ComponentType) === DropdownMenu) {
          return injectDropdownMenuShellProps(
            child as React.ReactElement<DropdownMenuProps>,
          ) as React.ReactElement<DropdownMenuProps>;
        }

        if ((child.type as React.ComponentType) === DropdownMenuFromDefinitions) {
          const sourceDefinitions = filteredDefinitions ?? resolvedDefinitions ?? [];
          const withFilteredDefinitions = React.cloneElement(
            child as React.ReactElement<DropdownMenuFromDefinitionsProps>,
            { definitions: sourceDefinitions },
          );
          return injectDropdownMenuShellProps(withFilteredDefinitions);
        }

        type GenericElementProps = Record<string, unknown> & {
          onClick?: (event: React.MouseEvent<HTMLElement>) => void;
        };

        const element = child as React.ReactElement<GenericElementProps>;

        return React.cloneElement(element, {
          onClick: (e: React.MouseEvent<HTMLElement>) => {
            e.stopPropagation();
            handleItemSelect(undefined, e);
            element.props.onClick?.(e);
          },
        });
      });
    }, [menuBodyFromItems, children, handleItemSelect, injectDropdownMenuShellProps]);

    const isAsyncLoading = shouldUseAsyncItems && asyncStatus === 'loading';
    const isAsyncError = shouldUseAsyncItems && asyncStatus === 'error';
    const combinedLoading = loading || isAsyncLoading;

    const errorMessage =
      asyncError instanceof Error ? asyncError.message : 'Не удалось загрузить список';

    const asyncErrorView = (
      <DropdownLoadingState role="alert" aria-live="assertive">
        <span>{errorMessage}</span>
        <Button variant={ButtonVariant.SECONDARY} size={Size.SM} onClick={handleRetryLoadItems}>
          Повторить
        </Button>
      </DropdownLoadingState>
    );

    const errorContent = renderErrorState?.(asyncError, handleRetryLoadItems) ?? asyncErrorView;
    const emptyStateView = renderEmptyState?.() ?? (
      <DropdownEmptyState>{emptyMessage}</DropdownEmptyState>
    );
    const hasDefinitionsMenuChild = React.useMemo(
      () =>
        React.Children.toArray(children).some(
          (node) =>
            React.isValidElement(node) &&
            (node.type as React.ComponentType) === DropdownMenuFromDefinitions,
        ),
      [children],
    );

    const hasDeclarativeItems = Boolean(items || asyncItems || hasDefinitionsMenuChild);

    const dropdownBody = combinedLoading ? (
      <DropdownLoadingState role="status" aria-live="polite">
        <DropdownLoadingSpinner aria-hidden="true" />
        <span>Загрузка...</span>
      </DropdownLoadingState>
    ) : isAsyncError ? (
      errorContent
    ) : (
      (renderChildren ?? (hasDeclarativeItems ? emptyStateView : null))
    );

    const topPanel = renderTopPanel
      ? renderTopPanel({
          size,
          variant,
          disabled,
        })
      : null;

    const bottomPanel = renderBottomPanel
      ? renderBottomPanel({
          size,
          variant,
          disabled,
        })
      : null;

    /** В `inline` меню внутри контейнера — колбэки только на корне; в портале панель вне DOM-дерева триггера — дублируем на `DropdownContent`. */
    const dropdownContentFocusProps:
      | Pick<DropdownProps, 'onFocus' | 'onBlur'>
      | Record<string, never> = inline ? {} : { onFocus, onBlur };

    const dropdownContent = (
      <DropdownContent
        ref={menuRef}
        $isOpen={isOpen}
        $position={position}
        $size={size}
        $variant={variant}
        $menuWidth={menuWidth}
        $menuMaxHeight={menuMaxHeight}
        $dropContainerCssMixin={dropContainerCssMixin}
        $inline={inline}
        $menuDensity={menuDensity}
        style={dropContainerStyle}
        onScrollCapture={onMenuScroll || onMenuLoadMore ? handleMenuScrollCapture : undefined}
        {...dropdownContentFocusProps}
      >
        {topPanel && <DropdownTopPanel>{topPanel}</DropdownTopPanel>}
        {searchable && !combinedLoading && (
          <DropdownSearchContainer>
            <DropdownSearchInput
              type="search"
              value={currentSearchValue}
              placeholder={searchPlaceholder}
              onChange={(changeEvent: React.ChangeEvent<HTMLInputElement>) => {
                handleSearchChange(changeEvent.target.value);
                onSearchInputChange?.(changeEvent);
              }}
            />
          </DropdownSearchContainer>
        )}
        {dropdownBody}
        {bottomPanel && <DropdownBottomPanel>{bottomPanel}</DropdownBottomPanel>}
      </DropdownContent>
    );

    return (
      <>
        <DropdownContainer
          ref={dropdownRef}
          $alignSelf={alignSelf}
          $fullWidth={fullWidth}
          className={clsx('ui-dropdown', className, { 'ui-dropdown--disabled': disabled })}
          onFocus={onFocus}
          onBlur={onBlur}
        >
          {trigger ? (
            <div
              onClick={triggerWrapClickToggle ? handleTriggerClick : undefined}
              style={{
                cursor: disabled ? 'not-allowed' : 'pointer',
                opacity: disabled ? 0.6 : 1,
                ...(fullWidth
                  ? { width: '100%', display: 'block', boxSizing: 'border-box' as const }
                  : {}),
              }}
            >
              {trigger}
            </div>
          ) : defaultTriggerKind === 'tag' ? (
            <DefaultTriggerTag
              ref={defaultTagTriggerRef}
              onToggle={handleTriggerClick}
              buttonProps={buttonProps}
              tagTriggerProps={tagTriggerProps}
              skeleton={skeleton}
              disabled={disabled}
              fieldSize={size}
              openMenuIconProps={openMenuIconProps}
              items={items}
              value={value}
              multiSelection={multiSelection}
              labelFromSelection={labelFromSelection}
              tagTriggerShowChevron={tagTriggerShowChevron}
              isMenuOpen={isOpen}
            />
          ) : (
            <DefaultTriggerButton
              ref={defaultButtonTriggerRef}
              onToggle={handleTriggerClick}
              buttonProps={buttonProps}
              skeleton={skeleton}
              disabled={disabled}
              fieldSize={size}
              openMenuIconProps={openMenuIconProps}
            />
          )}
          {shouldRender && inline && dropdownContent}
        </DropdownContainer>

        {shouldRender &&
          !inline &&
          typeof document !== 'undefined' &&
          createPortal(dropdownContent, portalContainer ?? document.body)}
      </>
    );
  },
);

Dropdown.displayName = 'Dropdown';

interface DefaultTriggerButtonProps {
  onToggle: () => void;
  buttonProps?: DropdownProps['buttonProps'];
  skeleton?: boolean;
  disabled?: boolean;
  /** Размер строки `Dropdown` — для шеврона рядом с дефолтной кнопкой */
  fieldSize?: Size;
  openMenuIconProps?: DropdownProps['openMenuIconProps'];
}

const DefaultTriggerButton = React.forwardRef<HTMLButtonElement, DefaultTriggerButtonProps>(
  (
    {
      onToggle,
      buttonProps,
      skeleton = false,
      disabled = false,
      fieldSize = Size.MD,
      openMenuIconProps,
    },
    ref,
  ) => {
    const {
      children,
      onClick,
      variant,
      fullWidth,
      size,
      disabled: buttonDisabled,
      ...restButtonProps
    } = buttonProps || {};

    // disabled из Dropdown имеет приоритет над disabled из buttonProps
    const isDisabled = disabled || buttonDisabled;

    const handleButtonClick = (event: React.MouseEvent<HTMLButtonElement>) => {
      if (skeleton) return;
      onToggle();
      onClick?.(event);
    };

    const openMenuIcon = (
      <Icon
        name="IconPlainerChevronDown"
        size={getChevronIconSizeForField(fieldSize)}
        color="currentColor"
        {...openMenuIconProps}
      />
    );

    return (
      <Button
        {...(restButtonProps as React.ComponentProps<typeof Button>)}
        ref={ref}
        onClick={handleButtonClick}
        variant={skeleton ? ButtonVariant.SKELETON : variant}
        size={size}
        fullWidth={fullWidth}
        disabled={isDisabled}
        iconEnd={openMenuIcon}
      >
        {children ?? 'Открыть меню'}
      </Button>
    );
  },
);

DefaultTriggerButton.displayName = 'DefaultTriggerButton';

import React from 'react';
import { clsx } from 'clsx';
import { TooltipPosition, type DropdownMenuItemProps } from '../../../types/ui';
import { Hint, HintVariant } from '../Hint/Hint';
import { mapTooltipPositionToHintPlacement } from './handlers';
import {
  DropdownItem,
  DropdownItemContent,
  DropdownItemDescription,
  DropdownItemIconSlot,
  DropdownItemLabel,
  DropdownItemLoadingSpinner,
  DropdownItemRightSlot,
  DropdownItemShortcut,
  DropdownMenuTreeChevronFrame,
  DropdownMenuTreeExpandButton,
  DropdownMenuTreeNestedList,
} from './Dropdown.style';
import { Skeleton } from '../Skeleton/Skeleton';
import { Checkbox } from '../Checkbox/Checkbox';
import { Size } from '../../../types/sizes';
import { Icon } from '../Icon/Icon';
import { getChevronIconSizeForField } from '../../../handlers/iconHandlers';
import {
  buildDropdownTreeBranchKey,
  collectSelectableValuesFromTreeItem,
  getTreeParentCheckboxVisualState,
} from '../../../handlers/dropdownTreeSelectionHandlers';
import {
  isSelectedInMultiSelection as checkIsSelectedInMultiSelection,
  calculateMenuItemState,
  getMenuItemKey,
} from './handlers';
import { useDropdownMenuContext } from './DropdownMenu';
import { Tooltip } from '../Tooltip/Tooltip';

/**
 * Элемент выпадающего меню с поддержкой иконок, описания и шорткатов
 */
export const DropdownMenuItem = React.forwardRef<HTMLDivElement, DropdownMenuItemProps>(
  (
    {
      label,
      description,
      value,
      icon,
      id,
      rightSlot,
      shortcut,
      disabled = false,
      loading = false,
      skeleton = false,
      tone = 'default',
      state,
      selected: propSelected,
      onSelect,
      children,
      className,
      showTooltip = false,
      tooltipText,
      tooltip,
      tooltipType = 'tooltip',
      tooltipPosition = TooltipPosition.TOP,
      nestedItems,
      treeAncestorKey,
      treeIndex = 0,
      onClick: itemRowClick,
      ...rest
    },
    ref,
  ) => {
    const {
      onItemSelect,
      value: selectedValue,
      onActivateItem,
      multiSelection,
      showCheckbox: showCheckboxFromMenu,
      disableSelectedOptionHighlight,
      menuDensity,
      size: menuSize,
      treeExpandable: treeExpandableFromMenu = true,
      isTreeBranchExpanded,
      toggleTreeBranch,
      lookupTreeMenuItemByValue,
    } = useDropdownMenuContext();

    const hasNestedTree = Boolean(nestedItems?.length);
    const branchKey = React.useMemo(
      () => buildDropdownTreeBranchKey(treeAncestorKey ?? '', { id, value, label }, treeIndex),
      [treeAncestorKey, id, value, label, treeIndex],
    );
    const treeBranchExpanded = !hasNestedTree || (isTreeBranchExpanded?.(branchKey) ?? true);

    /** Чекбоксы в мультивыборе: по умолчанию показываем, пока родитель не передал `showCheckbox={false}` */
    const showMultiCheckbox = Boolean(multiSelection && showCheckboxFromMenu !== false);

    /** Плотные строки для календаря и др. */
    const itemDensity = menuDensity === 'compact' ? 'compact' : undefined;
    const itemSize = menuSize ?? Size.MD;

    const isDisabled = disabled || loading || skeleton;

    // Определяем выбранное состояние для multiSelection
    const isSelectedInMultiSelection = React.useMemo(
      () => checkIsSelectedInMultiSelection(multiSelection, propSelected, selectedValue, value),
      [multiSelection, propSelected, selectedValue, value],
    );

    // Определяем финальное состояние: state имеет приоритет над сравнением value с selectedValue
    const finalState = React.useMemo(
      () =>
        calculateMenuItemState(
          disableSelectedOptionHighlight ?? false,
          state,
          multiSelection ?? false,
          selectedValue,
          value,
        ),
      [disableSelectedOptionHighlight, state, multiSelection, selectedValue, value],
    );

    const handleClick = (event: React.MouseEvent<HTMLDivElement>) => {
      if (isDisabled) {
        event.preventDefault();
        event.stopPropagation();
        return;
      }

      event.stopPropagation();

      // В режиме multiSelection клик на элемент меню также вызывает выбор
      // но меню не должно закрываться (это обрабатывается в handleItemSelect)
      onSelect?.(value, event);
      onItemSelect?.(value, event);
    };

    /** Сначала выбор строки, затем опциональный `onClick` с пропсов (`{...rest}` не должен перезаписывать выбор). */
    const handleRowClick = (event: React.MouseEvent<HTMLDivElement>) => {
      handleClick(event);
      itemRowClick?.(event);
    };

    const treeSelfItem = React.useMemo(
      () =>
        ({
          value,
          id,
          disabled,
          nestedItems,
          label,
        }) as DropdownMenuItemProps,
      [value, id, disabled, nestedItems, label],
    );

    /**
     * Полное поддерево для каскада чекбокса (селект с поиском режет `nestedItems` у пункта в панели).
     * TODO(tree-multiselect): снятие выбора по чекбоксу родителя после выбора только детей всё ещё может не
     * совпадать со строкой — разобрать цепочку событий / controlled Checkbox и добить поведение; пометка на доработку.
     */
    const resolvedTreeItemForCheckbox = React.useMemo(() => {
      if (!hasNestedTree || value === undefined || value === null) {
        return treeSelfItem;
      }
      const resolvedNode = lookupTreeMenuItemByValue?.(String(value));
      return resolvedNode ?? treeSelfItem;
    }, [hasNestedTree, value, lookupTreeMenuItemByValue, treeSelfItem]);

    const checkboxVisualState = React.useMemo(() => {
      if (!multiSelection || !hasNestedTree || !Array.isArray(selectedValue)) {
        return {
          checked: isSelectedInMultiSelection,
          indeterminate: false,
        };
      }
      return getTreeParentCheckboxVisualState(resolvedTreeItemForCheckbox, selectedValue);
    }, [
      multiSelection,
      hasNestedTree,
      selectedValue,
      resolvedTreeItemForCheckbox,
      isSelectedInMultiSelection,
    ]);

    const handleCheckboxChange = React.useCallback(
      (event: React.ChangeEvent<HTMLInputElement>) => {
        if (isDisabled) {
          event.preventDefault();
          event.stopPropagation();
          return;
        }

        event.stopPropagation();
        if (multiSelection && hasNestedTree) {
          /**
           * Совпадает с логикой строки: в поддереве (по полному узлу из lookup) уже есть выбранные значения — снять ветку (`false`);
           * иначе — ориентируемся на `target.checked` для включения.
           * TODO(tree-multiselect): см. комментарий у `resolvedTreeItemForCheckbox` — при необходимости пересмотреть всю ветку `handleCheckboxChange`.
           */
          const subtreeValueKeys = collectSelectableValuesFromTreeItem(resolvedTreeItemForCheckbox);
          const selectedStrings = Array.isArray(selectedValue)
            ? selectedValue.map((entry) => String(entry))
            : [];
          const selectedSetForSubtree = new Set(selectedStrings);
          const subtreeHasSelectedValue = subtreeValueKeys.some((subtreeKey) =>
            selectedSetForSubtree.has(subtreeKey),
          );
          const rawChecked = event.target.checked;
          const effectiveTreeCheckboxChecked = subtreeHasSelectedValue
            ? false
            : rawChecked !== false;
          /** Отдельный объект — не мутируем `ChangeEvent`, иначе на всплытии к строке меню можно прочитать «чужой» флаг. */
          const treeCheckboxEvent = {
            dropdownTreeCheckboxChecked: effectiveTreeCheckboxChecked,
          } as unknown as React.MouseEvent<HTMLDivElement>;
          onSelect?.(value, treeCheckboxEvent);
          onItemSelect?.(value, treeCheckboxEvent as unknown as React.MouseEvent<HTMLElement>);
          return;
        }
        onSelect?.(value, event as unknown as React.MouseEvent<HTMLDivElement>);
        onItemSelect?.(value, event as unknown as React.MouseEvent<HTMLElement>);
      },
      [
        isDisabled,
        onSelect,
        onItemSelect,
        value,
        multiSelection,
        hasNestedTree,
        resolvedTreeItemForCheckbox,
        selectedValue,
      ],
    );

    const handleMouseEnter = () => {
      if (!isDisabled) {
        onActivateItem?.(value);
      }
    };

    const trailingSlot =
      !loading &&
      !skeleton &&
      (rightSlot ?? (shortcut ? <DropdownItemShortcut>{shortcut}</DropdownItemShortcut> : null));

    const hasStructuredContent = Boolean(label || description);

    const structuredContent = hasStructuredContent ? (
      <>
        {label && <DropdownItemLabel $tone={tone}>{label}</DropdownItemLabel>}
        {description && <DropdownItemDescription>{description}</DropdownItemDescription>}
        {children}
      </>
    ) : (
      children
    );

    const resolvedContent =
      structuredContent ??
      (loading ? (
        <DropdownItemLabel $tone={tone}>Загрузка...</DropdownItemLabel>
      ) : (
        <DropdownItemLabel $tone={tone}>—</DropdownItemLabel>
      ));

    // В режиме multiSelection показываем чекбокс вместо иконки или вместе с иконкой
    const leftSlot = React.useMemo(() => {
      if (loading) {
        return <DropdownItemLoadingSpinner role="progressbar" aria-label="Загрузка" />;
      }

      if (showMultiCheckbox) {
        return (
          <DropdownItemIconSlot
            onClick={(iconSlotClick: React.MouseEvent<HTMLSpanElement>) => {
              // Клик по чекбоксу не должен всплывать к строке меню: второй onItemSelect с «чистым» MouseEvent ломает каскад дерева.
              iconSlotClick.stopPropagation();
            }}
          >
            <Checkbox
              checked={checkboxVisualState.checked}
              indeterminate={checkboxVisualState.indeterminate}
              onChange={handleCheckboxChange}
              disabled={isDisabled}
              size={Size.SM}
            />
          </DropdownItemIconSlot>
        );
      }

      if (icon) {
        return <DropdownItemIconSlot>{icon}</DropdownItemIconSlot>;
      }

      return null;
    }, [
      loading,
      showMultiCheckbox,
      checkboxVisualState.checked,
      checkboxVisualState.indeterminate,
      handleCheckboxChange,
      isDisabled,
      icon,
    ]);

    const expandControl =
      hasNestedTree && treeExpandableFromMenu ? (
        <DropdownMenuTreeExpandButton
          type="button"
          aria-expanded={treeBranchExpanded}
          aria-label={
            treeBranchExpanded ? 'Свернуть вложенный список' : 'Развернуть вложенный список'
          }
          onClick={(expandEvent: React.MouseEvent<HTMLButtonElement>) => {
            if (branchKey) {
              toggleTreeBranch?.(branchKey, expandEvent);
            }
          }}
        >
          <DropdownMenuTreeChevronFrame $expanded={treeBranchExpanded}>
            <Icon
              name="IconPlainerChevronDown"
              size={getChevronIconSizeForField(Size.SM)}
              color="currentColor"
            />
          </DropdownMenuTreeChevronFrame>
        </DropdownMenuTreeExpandButton>
      ) : null;

    const skeletonNode = (
      <DropdownItem
        ref={ref}
        role="menuitem"
        aria-disabled={true}
        tabIndex={-1}
        data-tone={tone}
        data-skeleton={true}
        data-dropdown-item-value={value !== undefined && value !== null ? String(value) : undefined}
        data-dropdown-item-id={id}
        $state={finalState}
        $size={itemSize}
        $density={itemDensity}
        className={clsx('ui-dropdown-menu-item', className)}
        onClick={handleRowClick}
        onMouseEnter={handleMouseEnter}
        style={{ padding: 0 }}
        {...(rest as Omit<typeof rest, 'style'>)}
      >
        <Skeleton
          width="100%"
          height="32px"
          style={{
            borderRadius: 'inherit',
          }}
        />
      </DropdownItem>
    );

    const regularRow = (
      <DropdownItem
        ref={ref}
        role="menuitem"
        aria-disabled={isDisabled}
        tabIndex={isDisabled ? -1 : 0}
        data-tone={tone}
        data-loading={loading}
        data-dropdown-item-value={value !== undefined && value !== null ? String(value) : undefined}
        data-dropdown-item-id={id}
        $state={finalState}
        $size={itemSize}
        $density={itemDensity}
        className={clsx('ui-dropdown-menu-item', className)}
        onClick={handleRowClick}
        onMouseEnter={handleMouseEnter}
        {...rest}
      >
        {expandControl}
        {leftSlot}
        <DropdownItemContent>{resolvedContent}</DropdownItemContent>
        {trailingSlot ? <DropdownItemRightSlot>{trailingSlot}</DropdownItemRightSlot> : null}
      </DropdownItem>
    );

    const nestedTreeBlock =
      hasNestedTree && treeBranchExpanded && nestedItems?.length ? (
        <DropdownMenuTreeNestedList role="group">
          {nestedItems.map((childItem, childIndex) => (
            <DropdownMenuItem
              key={getMenuItemKey(childItem, childIndex)}
              {...childItem}
              treeAncestorKey={branchKey}
              treeIndex={childIndex}
            />
          ))}
        </DropdownMenuTreeNestedList>
      ) : null;

    const regularNode = (
      <>
        {regularRow}
        {nestedTreeBlock}
      </>
    );

    const itemNode = skeleton ? skeletonNode : regularNode;

    const resolvedTooltipContent =
      tooltip ?? (showTooltip ? (tooltipText ?? label ?? description) : null);
    /** Для `disabled` / `loading` / `skeleton` подсказку у пункта не показываем (как у `Tooltip` с `disabled`). */
    const isItemHelpSuppressed = isDisabled || skeleton || loading;

    if (resolvedTooltipContent) {
      if (tooltipType === 'hint') {
        if (isItemHelpSuppressed) {
          return itemNode;
        }
        return (
          <Hint
            content={resolvedTooltipContent}
            placement={mapTooltipPositionToHintPlacement(tooltipPosition)}
            variant={HintVariant.DEFAULT}
          >
            {itemNode}
          </Hint>
        );
      }

      return (
        <Tooltip
          content={resolvedTooltipContent}
          position={tooltipPosition}
          disabled={isItemHelpSuppressed}
        >
          {itemNode}
        </Tooltip>
      );
    }

    return itemNode;
  },
);

DropdownMenuItem.displayName = 'DropdownMenuItem';

import type { DropdownTheme } from '../../../types/theme';
import type { Size } from '../../../types/sizes';
import { getDropdownItemStyles } from '../../../handlers/dropdownThemeHandlers';
import type React from 'react';
import type {
  DropdownMenuGroup,
  DropdownMenuItemProps,
  DropdownPositioningMode,
  DropdownVirtualScrollConfig,
} from '../../../types/ui';
import { HintPosition, TooltipPosition } from '../../../types/ui';

/**
 * Вычисляет высоту элемента dropdown из темы
 * @param theme - тема dropdown
 * @param size - размер dropdown
 * @returns высота элемента в пикселях
 */
export const calculateItemHeightFromTheme = (theme: DropdownTheme, size: Size): number => {
  const styles = getDropdownItemStyles(theme, size);
  // padding может быть в формате "6px 16px" (вертикальный горизонтальный) или "6px"
  const paddingMatch = styles.padding.match(/(\d+)px(?:\s+(\d+)px)?/);
  const paddingVertical = paddingMatch ? parseFloat(paddingMatch[1]) : 6;
  // Если padding в формате "6px 16px", то вертикальный padding = 6px, иначе используем то же значение
  const paddingTop = paddingVertical;
  const paddingBottom = paddingVertical;
  const lineHeightMatch = styles.lineHeight.match(/(\d+\.?\d*)/);
  const lineHeight = lineHeightMatch ? parseFloat(lineHeightMatch[1]) : 1.6;
  const fontSizeMatch = styles.fontSize.match(/(\d+)px/);
  const fontSize = fontSizeMatch ? parseFloat(fontSizeMatch[1]) : 14;

  // Высота элемента = padding-top + padding-bottom + (fontSize * lineHeight)
  // gap НЕ включаем в высоту элемента, так как при абсолютном позиционировании
  // gap не применяется автоматически, и мы должны учитывать его в позиционировании
  const calculatedHeight = paddingTop + paddingBottom + fontSize * lineHeight;
  return Math.ceil(calculatedHeight);
};

/**
 * Получает gap между элементами из темы
 * @param theme - тема dropdown
 * @param size - размер dropdown
 * @returns gap в пикселях
 */
export const getGapFromTheme = (theme: DropdownTheme, size: Size): number => {
  const styles = getDropdownItemStyles(theme, size);
  const gapMatch = styles.gap?.match(/(\d+)px/);
  return gapMatch ? parseFloat(gapMatch[1]) : 4;
};

/**
 * Вычисляет фиксированную высоту контейнера на основе maxHeight
 * @param itemHeight - высота одного элемента
 * @param gap - gap между элементами
 * @returns фиксированная высота контейнера для 8 элементов
 */
export const calculateFixedContainerHeight = (itemHeight: number, gap: number): number => {
  const itemHeightWithGap = itemHeight + gap;
  return itemHeightWithGap * 8;
};

/**
 * Вычисляет видимый диапазон элементов для виртуального скролла
 * @param scrollTop - текущая позиция скролла
 * @param containerHeight - высота контейнера
 * @param itemHeight - высота одного элемента
 * @param gap - gap между элементами
 * @param totalItems - общее количество элементов
 * @returns объект с начальным и конечным индексами видимых элементов
 */
export const calculateVisibleRange = (
  scrollTop: number,
  containerHeight: number | null,
  itemHeight: number,
  gap: number,
  totalItems: number,
): { start: number; end: number } => {
  const itemHeightWithGap = itemHeight + gap;
  const effectiveHeight = containerHeight || itemHeightWithGap * 8;

  // Учитываем gap при расчете индекса начала
  const startIndex = Math.floor(scrollTop / itemHeightWithGap);
  const visibleCount = Math.ceil(effectiveHeight / itemHeightWithGap);
  // Добавляем буфер сверху и снизу для плавного скролла (по 2 элемента с каждой стороны)
  const buffer = 2;
  const endIndex = Math.min(startIndex + visibleCount + buffer, totalItems);

  return {
    start: Math.max(0, startIndex - buffer), // Буфер сверху
    end: endIndex,
  };
};

/**
 * Вычисляет общую высоту контента для виртуального скролла
 * @param totalItems - общее количество элементов
 * @param itemHeight - высота одного элемента
 * @param gap - gap между элементами
 * @returns общая высота контента в пикселях
 */
export const calculateTotalHeight = (
  totalItems: number,
  itemHeight: number,
  gap: number,
): number => {
  if (totalItems === 0) return 0;
  const itemHeightWithGap = itemHeight + gap;
  // Учитываем gap между элементами: (n элементов) * (высота + gap) - gap (последний элемент не имеет gap снизу)
  return totalItems * itemHeightWithGap - gap;
};

/**
 * Определяет, выбран ли элемент в режиме multiSelection
 * @param multiSelection - включен ли режим множественного выбора
 * @param propSelected - явно заданное состояние выбранности из пропсов
 * @param selectedValue - значение выбранного элемента из контекста (может быть массивом)
 * @param value - значение текущего элемента
 * @returns true, если элемент выбран
 */
export const isSelectedInMultiSelection = (
  multiSelection: boolean | undefined,
  propSelected: boolean | undefined,
  selectedValue: unknown,
  value: unknown,
): boolean => {
  if (!multiSelection) return false;
  if (propSelected !== undefined) return propSelected;
  if (Array.isArray(selectedValue)) {
    return selectedValue.includes(value);
  }
  return false;
};

/**
 * Определяет финальное состояние элемента меню
 * @param disableSelectedOptionHighlight - отключена ли подсветка выбранной опции
 * @param state - явно заданное состояние из пропсов
 * @param multiSelection - включен ли режим множественного выбора
 * @param selectedValue - значение выбранного элемента из контекста
 * @param value - значение текущего элемента
 * @returns финальное состояние элемента или undefined
 */
export const calculateMenuItemState = (
  disableSelectedOptionHighlight: boolean | undefined,
  state: 'hover' | 'active' | 'disabled' | 'selected' | 'focus' | undefined,
  multiSelection: boolean | undefined,
  selectedValue: unknown,
  value: unknown,
): 'hover' | 'active' | 'disabled' | 'selected' | 'focus' | undefined => {
  if (disableSelectedOptionHighlight) {
    return undefined;
  }

  // Если state задан явно, используем его
  if (state) {
    return state;
  }

  // В режиме multiSelection проверяем, выбран ли элемент через массив
  if (multiSelection) {
    if (Array.isArray(selectedValue) && selectedValue.includes(value)) {
      return 'selected';
    }
    return undefined;
  }

  // В обычном режиме проверяем равенство значения
  if (selectedValue !== undefined && value === selectedValue) {
    return 'selected';
  }

  return undefined;
};

/**
 * Вычисляет позицию элемента в виртуальном скролле
 * @param index - индекс элемента
 * @param itemHeight - высота одного элемента
 * @param gap - gap между элементами
 * @returns позиция top в пикселях
 */
export const calculateItemPosition = (index: number, itemHeight: number, gap: number): number => {
  return index * (itemHeight + gap);
};

/**
 * Создает стили для контейнера виртуального скролла
 * @param fixedContainerHeight - фиксированная высота контейнера
 * @param itemHeight - высота одного элемента
 * @param gap - gap между элементами
 * @returns объект со стилями для контейнера
 */
export const getVirtualScrollContainerStyles = (
  fixedContainerHeight: number | null,
  itemHeight: number | null,
  gap: number,
): React.CSSProperties | undefined => {
  if (!fixedContainerHeight && !itemHeight) return undefined;

  if (fixedContainerHeight) {
    return {
      overflowY: 'auto',
      overflowX: 'hidden',
      height: `${fixedContainerHeight}px`,
      position: 'relative',
    };
  }

  if (itemHeight) {
    return {
      overflowY: 'auto',
      overflowX: 'hidden',
      maxHeight: `${(itemHeight + gap) * 8}px`,
      position: 'relative',
    };
  }

  return undefined;
};

/**
 * Создает стили для внутреннего контейнера виртуального скролла
 * @param totalHeight - общая высота контента
 * @returns объект со стилями для внутреннего контейнера
 */
export const getVirtualScrollInnerContainerStyles = (totalHeight: number): React.CSSProperties => {
  return {
    height: `${totalHeight}px`,
    minHeight: `${totalHeight}px`,
    maxHeight: `${totalHeight}px`,
    position: 'relative',
    boxSizing: 'border-box',
    contain: 'layout size',
  };
};

/**
 * Вычисляет позицию dropdown относительно элемента
 * @param element - элемент, относительно которого позиционируется dropdown
 * @param offset - отступ от элемента (по умолчанию 4px)
 * @returns объект с координатами x и y
 */
const clamp = (value: number, min: number, max: number): number => {
  if (Number.isNaN(value)) return min;
  return Math.min(Math.max(value, min), max);
};

export interface CalculateDropdownPositionOptions {
  triggerElement: HTMLElement | null;
  menuElement?: HTMLElement | null;
  boundaryElement?: HTMLElement | null;
  offset?: number;
  mode?: DropdownPositioningMode;
  /**
   * **below** — классика под триггером; **rightStart** — панель справа, верх совпадает с триггером (подменю сайдбара).
   */
  preferredPlacement?: 'below' | 'rightStart';
}

export const calculateDropdownPosition = ({
  triggerElement,
  menuElement,
  boundaryElement,
  offset = 4,
  mode = 'default',
  preferredPlacement = 'below',
}: CalculateDropdownPositionOptions): { x: number; y: number } => {
  if (!triggerElement) return { x: 0, y: 0 };

  const triggerRect = triggerElement.getBoundingClientRect();
  const menuRect = menuElement?.getBoundingClientRect();
  const viewportWidth = window.innerWidth;
  const viewportHeight = window.innerHeight;
  const menuWidth = menuRect?.width ?? 0;
  const menuHeight = menuRect?.height ?? 0;

  if (preferredPlacement === 'rightStart') {
    let xRight = triggerRect.right + offset;
    let yTop = triggerRect.top;

    if (menuWidth > 0 && xRight + menuWidth > viewportWidth - offset) {
      xRight = triggerRect.left - menuWidth - offset;
    }
    if (menuWidth > 0) {
      xRight = clamp(xRight, offset, viewportWidth - menuWidth - offset);
    }

    if (menuHeight > 0) {
      yTop = clamp(yTop, offset, viewportHeight - menuHeight - offset);
    }

    let x = xRight;
    let y = yTop;

    if (boundaryElement) {
      const boundaryRect = boundaryElement.getBoundingClientRect();
      x -= boundaryRect.left;
      y -= boundaryRect.top;
      if (menuWidth > 0 && menuHeight > 0) {
        x = clamp(x, 0, (boundaryElement.clientWidth || viewportWidth) - menuWidth);
        y = clamp(y, 0, (boundaryElement.clientHeight || viewportHeight) - menuHeight);
      }
    }

    return { x, y };
  }

  let x = triggerRect.left;
  let y = triggerRect.bottom + offset;

  // Flip / горизонтальная подгонка только при известных размерах меню и не в режиме `default`
  if (menuRect && mode !== 'default') {
    const menuHeight = menuRect.height;
    const menuWidth = menuRect.width;
    const spaceBelow = viewportHeight - triggerRect.bottom;
    const spaceAbove = triggerRect.top;

    const shouldFlipVertically =
      menuHeight > 0 &&
      spaceBelow < menuHeight + offset &&
      (mode === 'autoFit' || spaceAbove >= menuHeight + offset || spaceAbove > spaceBelow);

    if (shouldFlipVertically) {
      y = clamp(
        triggerRect.top - menuHeight - offset,
        offset,
        viewportHeight - menuHeight - offset,
      );
    } else if (triggerRect.bottom + menuHeight + offset > viewportHeight) {
      y = clamp(viewportHeight - menuHeight - offset, offset, triggerRect.bottom + offset);
    }

    if (mode === 'autoFit' && menuWidth > 0) {
      const maxX = viewportWidth - menuWidth - offset;
      if (triggerRect.left + menuWidth > viewportWidth) {
        x = clamp(maxX, offset, triggerRect.right - menuWidth);
      }
      if (x < offset) {
        x = offset;
      }
    }
  }

  // Внутренний режим (`inline`): координаты должны быть относительно boundary, иначе `absolute`
  // получает значения вьюпорта и меню «улетает» (как у Select с панелью внутри формы).
  if (boundaryElement) {
    const boundaryRect = boundaryElement.getBoundingClientRect();
    x -= boundaryRect.left;
    y -= boundaryRect.top;
    if (menuRect && menuRect.width > 0 && menuRect.height > 0) {
      x = clamp(x, 0, (boundaryElement.clientWidth || viewportWidth) - menuRect.width);
      y = clamp(y, 0, (boundaryElement.clientHeight || viewportHeight) - menuRect.height);
    }
  }

  return { x, y };
};

const FOCUSABLE_SELECTORS =
  'a[href], button:not([disabled]), textarea:not([disabled]), input:not([disabled]), select:not([disabled]), [tabindex]:not([tabindex="-1"])';

export const getFocusableElements = (container: HTMLElement | null): HTMLElement[] => {
  if (!container) return [];
  const elements = Array.from(container.querySelectorAll<HTMLElement>(FOCUSABLE_SELECTORS)).filter(
    (element) => {
      const isHidden = element.offsetParent === null && element !== document.activeElement;
      const isAriaDisabled = element.getAttribute('aria-disabled') === 'true';
      return !isHidden && !isAriaDisabled;
    },
  );
  return elements;
};

export const getFocusableElementIndex = (
  elements: HTMLElement[],
  target: Element | null,
): number => {
  if (!target) return 0;
  const index = elements.findIndex((element) => element === target);
  return index === -1 ? 0 : index;
};

/**
 * Нормализует значение для dropdown
 * В режиме multiSelection всегда возвращает массив
 * @param value - значение из пропсов
 * @param multiSelection - включен ли режим множественного выбора
 * @returns нормализованное значение (массив в multiSelection, иначе исходное значение)
 */
export const normalizeDropdownValue = <T>(
  value: T | T[] | undefined,
  multiSelection: boolean,
): T | T[] | undefined => {
  if (multiSelection) {
    // Если multiSelection включен, но value не массив, возвращаем пустой массив
    if (!Array.isArray(value)) {
      return [] as T[];
    }
    return value;
  }
  return value;
};

/**
 * Создает ключ для элемента меню
 * @param item - элемент меню (`value` и/или `label` для ключа; `label` нестрокового типа не используется как ключ)
 * @param index - индекс элемента
 * @returns ключ для React
 */
export const getMenuItemKey = (
  item: { value?: unknown; label?: React.ReactNode },
  index: number,
): React.Key => {
  if (item.value !== undefined && item.value !== null) {
    return item.value as React.Key;
  }
  if (typeof item.label === 'string' || typeof item.label === 'number') {
    return item.label;
  }
  return index;
};

/**
 * Проверяет, был ли клик внутри dropdown (триггер или меню)
 * @param event - событие клика
 * @param triggerRef - ref триггера
 * @param menuRef - ref меню
 * @returns true, если клик был внутри dropdown
 */
export const isClickInsideDropdown = (
  event: MouseEvent,
  triggerRef: React.RefObject<HTMLElement>,
  menuRef: React.RefObject<HTMLElement>,
): boolean => {
  const target = event.target as Node;
  const isClickInsideTrigger = triggerRef.current && triggerRef.current.contains(target);
  const isClickInsideMenu = menuRef.current && menuRef.current.contains(target);
  return Boolean(isClickInsideTrigger || isClickInsideMenu);
};

/**
 * Обрабатывает клик вне dropdown компонента
 * Проверяет, был ли клик вне компонента, и вызывает обработчик onClickOutside если он передан
 * @param event - событие клика
 * @param triggerRef - ref триггера
 * @param menuRef - ref меню
 * @param onClickOutside - обработчик клика вне компонента
 * @returns true, если клик был вне компонента
 */
export const handleClickOutsideEvent = (
  event: MouseEvent,
  triggerRef: React.RefObject<HTMLElement>,
  menuRef: React.RefObject<HTMLElement>,
  onClickOutside?: (event: Event) => void,
): boolean => {
  const isOutside = !isClickInsideDropdown(event, triggerRef, menuRef);

  if (isOutside && onClickOutside) {
    onClickOutside(event);
  }

  return isOutside;
};

/**
 * Находит все прокручиваемые родительские элементы
 * @param element - начальный элемент
 * @returns массив прокручиваемых элементов (Window, Document, HTMLElement)
 */
export const findScrollableParents = (
  element: HTMLElement | null,
): (Window | Document | HTMLElement)[] => {
  const scrollableElements: (Window | Document | HTMLElement)[] = [window, document];
  let parent: HTMLElement | null = element?.parentElement || null;

  while (parent) {
    const overflow = window.getComputedStyle(parent).overflow;
    if (overflow === 'auto' || overflow === 'scroll' || overflow === 'overlay') {
      scrollableElements.push(parent);
    }
    parent = parent.parentElement;
  }

  return scrollableElements;
};

/**
 * Удаляет обработчики скролла со всех прокручиваемых элементов
 * @param scrollableElements - массив прокручиваемых элементов
 * @param handleScroll - обработчик скролла
 */
export const removeScrollListeners = (
  scrollableElements: (Window | Document | HTMLElement)[],
  handleScroll: () => void,
): void => {
  scrollableElements.forEach((element) => {
    if (element === window) {
      window.removeEventListener('scroll', handleScroll, true);
    } else if (element === document) {
      document.removeEventListener('scroll', handleScroll, true);
    } else {
      (element as HTMLElement).removeEventListener('scroll', handleScroll, true);
    }
  });
};

/**
 * Вычисляет высоту элемента для виртуального скролла
 * @param virtualScroll - конфигурация виртуального скролла
 * @param theme - тема dropdown
 * @param size - размер dropdown
 * @returns высота элемента в пикселях или null, если виртуальный скролл не включен
 */
export const calculateVirtualScrollItemHeight = (
  virtualScroll: DropdownVirtualScrollConfig | undefined,
  theme: DropdownTheme,
  size: Size,
): number | null => {
  if (!virtualScroll) return null;

  if (virtualScroll.itemHeight === 'auto') {
    return calculateItemHeightFromTheme(theme, size);
  }

  return virtualScroll.itemHeight;
};

/**
 * Создает стили для позиционирования видимого элемента в виртуальном скролле
 * @param topPosition - позиция top в пикселях
 * @returns объект со стилями для элемента
 */
export const getVirtualScrollItemStyles = (topPosition: number): React.CSSProperties => {
  return {
    position: 'absolute',
    top: topPosition,
    width: '100%',
    left: 0,
    right: 0,
  };
};

/**
 * Проверяет, что запись — группа с вложенными пунктами (`items`), а не одиночный пункт.
 * @param entry - элемент списка определений меню
 */
export const isDropdownGroup = (
  entry: DropdownMenuItemProps | DropdownMenuGroup,
): entry is DropdownMenuGroup => {
  return Array.isArray((entry as DropdownMenuGroup)?.items);
};

/**
 * Разворачивает группы и одиночные пункты в один плоский список (порядок: как в дереве).
 * @param definitions - Элементы меню или группы
 * @returns Плоский массив пунктов
 */
export const flattenDropdownDefinitions = (
  definitions: (DropdownMenuItemProps | DropdownMenuGroup)[] | null | undefined,
): DropdownMenuItemProps[] => {
  if (!definitions?.length) {
    return [];
  }
  const out: DropdownMenuItemProps[] = [];
  definitions.forEach((def) => {
    if (isDropdownGroup(def)) {
      def.items.forEach((item) => out.push(item));
    } else {
      out.push(def);
    }
  });
  return out;
};

/**
 * Позиция `Hint` для пункта меню: значения совпадают с `TooltipPosition` для сторон света.
 * @param tooltipPosition - значение из пропса пункта (`top` | `bottom` | `left` | `right`)
 */
export const mapTooltipPositionToHintPlacement = (
  tooltipPosition: TooltipPosition,
): HintPosition => {
  switch (tooltipPosition) {
    case TooltipPosition.BOTTOM:
      return HintPosition.BOTTOM;
    case TooltipPosition.LEFT:
      return HintPosition.LEFT;
    case TooltipPosition.RIGHT:
      return HintPosition.RIGHT;
    case TooltipPosition.TOP:
    default:
      return HintPosition.TOP;
  }
};

import type { Dispatch, SetStateAction } from 'react';
import { createContext, useContext } from 'react';
import type { FloatingMenuDragSource } from '@/types/ui';
import { FloatingMenuGroupVariant } from '@/types/ui';

/** Контекст корня плавающего меню */
export interface FloatingMenuRootContextValue {
  draggable: boolean;
  dragSource: FloatingMenuDragSource;
  zIndex: number;
  /** id открытого выпадающего пункта (для взаимного закрытия) */
  openDropdownId: string | null;
  setOpenDropdownId: Dispatch<SetStateAction<string | null>>;
  /** Зарегистрирован ли дочерний DragHandle (для режима HANDLE) */
  hasDragHandle: boolean;
  setHasDragHandle: (v: boolean) => void;
}

export const FloatingMenuRootContext = createContext<FloatingMenuRootContextValue | undefined>(
  undefined,
);

export const useFloatingMenuRootContext = (): FloatingMenuRootContextValue => {
  const ctx = useContext(FloatingMenuRootContext);
  if (!ctx) {
    throw new Error('Компоненты FloatingMenu.* должны находиться внутри FloatingMenu');
  }
  return ctx;
};

/** Контекст группы (default / inset) */
export interface FloatingMenuGroupContextValue {
  variant: FloatingMenuGroupVariant;
}

export const FloatingMenuGroupContext = createContext<FloatingMenuGroupContextValue>({
  variant: FloatingMenuGroupVariant.DEFAULT,
});

export const useFloatingMenuGroupContext = (): FloatingMenuGroupContextValue =>
  useContext(FloatingMenuGroupContext);

import styled, { css } from 'styled-components';
import type { HintVariant, HintCssMixin, HintAnimationPreset } from '../../../types/ui';
import { HintPosition, HintAnimationPreset as AnimationPreset } from '../../../types/ui';
import { Size } from '../../../types/sizes';
import {
  buildHoverPressMotionCss,
  buildSurfaceTransitionCss,
  uiMotionSurfaceEasing,
} from '../../../handlers/uiMotionStyleHandlers';
import { ZIndexHandler } from '../../../handlers/uiHandlers';

/**
 * Внешний контейнер для hint (AnchorWrapper)
 */
export const AnchorWrapper = styled.div<{
  $anchorCssMixin?: HintCssMixin;
}>`
  display: inline-block;
  ${({ $anchorCssMixin }) => $anchorCssMixin ?? ''}
`;

/**
 * Триггер hint
 */
export const HintTrigger = styled.div`
  display: inline-block;
  cursor: help;
  transition: transform 0.12s ease;
  ${buildHoverPressMotionCss({
    hoverSelector: '&:hover',
    activeSelector: '&:active',
    hoverTransform: 'none',
    activeTransform: 'scale(0.98)',
  })}
`;

/**
 * Контент hint
 */
export const HintContent = styled.div<{
  $size?: Size;
  $isVisible: boolean;
  $position: { x: number; y: number };
  $placement?: HintPosition;
  $maxWidth?: number;
  $variant?: HintVariant;
  $clickable?: boolean;
  $showArrow?: boolean;
  $animationPreset?: HintAnimationPreset;
  $animationDuration?: number;
  $zIndex?: number;
  $mobile?: boolean;
}>`
  position: fixed;
  font-family: ${({ theme }) => theme.fonts.primary};
  font-weight: 500;
  z-index: ${({ $zIndex }) => $zIndex ?? ZIndexHandler('hint')};
  pointer-events: ${({ $isVisible, $clickable }) =>
    $isVisible ? ($clickable ? 'auto' : 'none') : 'none'};
  user-select: ${({ theme }) => theme.hints.settings.userSelect};
  cursor: ${({ $clickable }) => ($clickable ? 'pointer' : 'default')};
  max-width: ${({ $maxWidth, $mobile }) => ($mobile ? '90vw' : $maxWidth || 300)}px;
  word-wrap: ${({ theme }) => theme.hints.settings.wordWrap};
  white-space: ${({ theme }) => theme.hints.settings.whiteSpace};
  display: ${({ theme }) => theme.hints.settings.display};
  align-items: ${({ theme }) => theme.hints.settings.alignItems};
  justify-content: ${({ theme }) => theme.hints.settings.justifyContent};
  will-change: transform, opacity;

  /* Мобильный режим */
  ${({ $mobile }) =>
    $mobile &&
    css`
      font-size: 16px; /* Увеличенный размер для touch-интерфейса */
      padding: 12px 16px; /* Увеличенные отступы */
      max-width: 90vw;
      border-radius: 12px;
    `}

  /* Размеры из темы */
  ${({ $size = Size.MD, theme }) => {
    const sizeConfig = theme.hints.sizes[$size];
    return css`
      font-size: ${sizeConfig.fontSize};
      line-height: ${sizeConfig.lineHeight};
      padding: ${sizeConfig.padding};
      border-radius: ${sizeConfig.borderRadius};
      gap: ${sizeConfig.gap};
    `;
  }}

  /* Варианты из темы */
  ${({ $variant = 'default', theme }) => {
    const variantConfig = theme.hints.variants[$variant as keyof typeof theme.hints.variants];
    return css`
      background: ${variantConfig.background};
      color: ${variantConfig.color};
      border: ${variantConfig.border};
      box-shadow: ${variantConfig.boxShadow};
    `;
  }}

  /* Состояния из темы с учетом позиционирования и анимации (аналогично Tooltip) */
  ${({ $isVisible, $placement, $animationPreset = AnimationPreset.FADE, theme }) => {
    const stateConfig = $isVisible ? theme.hints.states.visible : theme.hints.states.hidden;

    // Определяем базовую трансформацию в зависимости от позиции (как в Tooltip)
    const baseTransform = (() => {
      if (!$placement) return 'translate(-50%, -50%)';

      if ($placement === HintPosition.TOP) {
        return 'translateX(-50%) translateY(-100%)';
      }
      if ($placement === HintPosition.BOTTOM) {
        return 'translateX(-50%)';
      }
      if ($placement === HintPosition.LEFT) {
        return 'translateY(-50%) translateX(-100%)';
      }
      if ($placement === HintPosition.RIGHT) {
        return 'translateY(-50%)';
      }
      // Для угловых позиций
      if ($placement === HintPosition.TOP_LEFT) {
        return 'translateY(-100%)';
      }
      if ($placement === HintPosition.TOP_RIGHT) {
        return 'translateX(-100%) translateY(-100%)';
      }
      if ($placement === HintPosition.BOTTOM_LEFT) {
        return '';
      }
      if ($placement === HintPosition.BOTTOM_RIGHT) {
        return 'translateX(-100%)';
      }
      return 'translate(-50%, -50%)';
    })();

    // Определяем трансформацию в зависимости от типа анимации
    let transform = baseTransform;
    if ($animationPreset === AnimationPreset.SCALE) {
      const scale = $isVisible ? 'scale(1)' : 'scale(0.8)';
      transform = `${baseTransform} ${scale}`;
    } else if ($animationPreset === AnimationPreset.SLIDE) {
      // Для slide добавляем смещение в зависимости от позиции
      if (!$isVisible) {
        let slideOffset = '';
        if ($placement === HintPosition.TOP) {
          slideOffset = 'translateY(10px)';
        } else if ($placement === HintPosition.BOTTOM) {
          slideOffset = 'translateY(-10px)';
        } else if ($placement === HintPosition.LEFT) {
          slideOffset = 'translateX(10px)';
        } else if ($placement === HintPosition.RIGHT) {
          slideOffset = 'translateX(-10px)';
        }
        if (slideOffset) {
          transform = `${baseTransform} ${slideOffset}`;
        } else {
          transform = `${baseTransform} scale(0.95)`;
        }
      } else {
        transform = baseTransform;
      }
    } else if ($animationPreset === AnimationPreset.FADE) {
      const scale = $isVisible ? 'scale(1)' : 'scale(0.95)';
      transform = `${baseTransform} ${scale}`;
    }

    return css`
      opacity: ${stateConfig.opacity};
      visibility: ${stateConfig.visibility};
      transform: ${transform};
    `;
  }}

  /* Анимация из темы или кастомная */
  ${({ $animationPreset = AnimationPreset.FADE, $animationDuration, theme }) => {
    const duration = $animationDuration ?? theme.hints.animations.duration;
    const durationMs = `${duration}ms`;

    switch ($animationPreset) {
      case AnimationPreset.FADE:
        return css`
          ${buildSurfaceTransitionCss(
            `opacity ${durationMs} ${uiMotionSurfaceEasing},
             visibility ${durationMs} ${uiMotionSurfaceEasing},
             transform ${durationMs} ${uiMotionSurfaceEasing}`,
          )}
        `;
      case AnimationPreset.SLIDE:
        return css`
          ${buildSurfaceTransitionCss(
            `opacity ${durationMs} ${theme.hints.animations.easing},
             visibility ${durationMs} ${theme.hints.animations.easing},
             transform ${durationMs} cubic-bezier(0.4, 0, 0.2, 1)`,
          )}
        `;
      case AnimationPreset.SCALE:
        return css`
          ${buildSurfaceTransitionCss(
            `opacity ${durationMs} ${theme.hints.animations.easing},
             visibility ${durationMs} ${theme.hints.animations.easing},
             transform ${durationMs} cubic-bezier(0.34, 1.56, 0.64, 1)`,
          )}
        `;
      case AnimationPreset.NONE:
        return buildSurfaceTransitionCss('none');
      default:
        return css`
          ${buildSurfaceTransitionCss(theme.hints.animations.transition)}
        `;
    }
  }}

  /* Позиционирование */
  left: ${({ $position }) => $position.x}px;
  top: ${({ $position }) => $position.y}px;

  /* Стрелка */
  ${({ $showArrow, $placement, $variant = 'default', $isVisible, theme }) => {
    if (!$showArrow) return '';

    const variantConfig = theme.hints.variants[$variant as keyof typeof theme.hints.variants];
    // Извлекаем цвет границы для стрелки (убираем "1px solid " если есть)
    const borderColor =
      variantConfig.border.replace(/^\d+px\s+solid\s+/, '') || variantConfig.border;

    return css`
      &::after {
        content: '';
        position: absolute;
        z-index: 1;
        opacity: ${$isVisible ? 1 : 0};
        transition: opacity 0.2s ease-in-out;

        ${() => {
          if ($placement === HintPosition.TOP) {
            return css`
              bottom: -8px;
              left: 50%;
              transform: translateX(-50%);
              width: 0;
              height: 0;
              border-left: 8px solid transparent;
              border-right: 8px solid transparent;
              border-top: 8px solid ${borderColor};
            `;
          }
          if ($placement === HintPosition.BOTTOM) {
            return css`
              top: -8px;
              left: 50%;
              transform: translateX(-50%);
              width: 0;
              height: 0;
              border-left: 8px solid transparent;
              border-right: 8px solid transparent;
              border-bottom: 8px solid ${borderColor};
            `;
          }
          if ($placement === HintPosition.LEFT) {
            return css`
              right: 0px;
              top: 50%;
              transform: translateY(-50%) translateX(50%);
              width: 0;
              height: 0;
              border-top: 8px solid transparent;
              border-bottom: 8px solid transparent;
              border-left: 8px solid ${borderColor};
            `;
          }
          if ($placement === HintPosition.RIGHT) {
            return css`
              left: 0px;
              top: 50%;
              transform: translateY(-50%) translateX(-50%);
              width: 0;
              height: 0;
              border-top: 8px solid transparent;
              border-bottom: 8px solid transparent;
              border-right: 8px solid ${borderColor};
            `;
          }
          // Для угловых позиций стрелка направлена к центру элемента
          if ($placement === HintPosition.TOP_LEFT) {
            return css`
              bottom: -8px;
              left: 12px;
              width: 0;
              height: 0;
              border-left: 8px solid transparent;
              border-right: 8px solid transparent;
              border-top: 8px solid ${borderColor};
            `;
          }
          if ($placement === HintPosition.TOP_RIGHT) {
            return css`
              bottom: -8px;
              right: 12px;
              width: 0;
              height: 0;
              border-left: 8px solid transparent;
              border-right: 8px solid transparent;
              border-top: 8px solid ${borderColor};
            `;
          }
          if ($placement === HintPosition.BOTTOM_LEFT) {
            return css`
              top: -8px;
              left: 12px;
              width: 0;
              height: 0;
              border-left: 8px solid transparent;
              border-right: 8px solid transparent;
              border-bottom: 8px solid ${borderColor};
            `;
          }
          if ($placement === HintPosition.BOTTOM_RIGHT) {
            return css`
              top: -8px;
              right: 12px;
              width: 0;
              height: 0;
              border-left: 8px solid transparent;
              border-right: 8px solid transparent;
              border-bottom: 8px solid ${borderColor};
            `;
          }
          return '';
        }}
      }
    `;
  }}
`;

