        rel={safeRel}
        download={download}
        className={clsx('ui-link', 'ui-link--button', className)}
        {...buttonProps}
      >
        {children}
      </Button>
    );
  }

  const {
    mode: _mode,
    textVariant = 'default',
    href: _h,
    target: _t,
    rel: _r,
    download: _d,
    className: _c,
    children: _ch,
    ...anchorRest
  } = props as LinkTextProps;

  return (
