  const activeBarText = primary;
  const activeHighlightBg =
    theme.mode === ThemeMode.DARK
      ? `color-mix(in srgb, ${primary} 18%, ${defaultBg})`
      : `color-mix(in srgb, ${primary} 12%, ${theme.colors.backgroundSecondary})`;

