import React, { useMemo } from 'react';
import type { SkeletonProps, SkeletonVariant } from '../../../types/ui';
import { SkeletonGroupDirection } from '../../../types/ui';
import { SkeletonGroup, SkeletonWrapper } from './Skeleton.style';

/**
 * Преобразует значение размера в CSS-строку
 */
const getSizeValue = (value?: number | string, fallback?: string): string => {
  if (typeof value === 'number') {
    return `${value}px`;
  }
  if (typeof value === 'string') {
    return value;
  }
  return fallback || '';
};

/**
 * Получает предустановленные размеры для вариантов
 */
const getVariantDimensions = (
  variant?: SkeletonVariant | 'text' | 'avatar' | 'button' | 'custom',
): { width?: string; height?: string; shape?: 'rect' | 'circle' } => {
  switch (variant) {
    case 'text':
      return { width: '100%', height: '16px', shape: 'rect' };
    case 'avatar':
      return { width: '48px', height: '48px', shape: 'circle' };
    case 'button':
      return { width: '120px', height: '40px', shape: 'rect' };
    default:
      return {};
  }
};

/** Нормализованные числовые параметры скелетона */
interface SkeletonNumericProps {
  count: number;
  gap: number;
  animationSpeed: number;
}

/**
 * Валидирует count, gap и скорость анимации
 * @param props — подмножество пропсов скелетона
 */
const validateNumericProps = (
  props: Pick<SkeletonProps, 'count' | 'gap' | 'animationSpeed'>,
): SkeletonNumericProps => {
  const count = props.count ?? 1;
  const gap = props.gap ?? 8;
  const animationSpeed = props.animationSpeed ?? 1.5;

  return {
    count: Math.max(1, Math.floor(count)),
    gap: Math.max(0, gap),
    animationSpeed: Math.max(0.1, Math.min(5, animationSpeed)),
  };
};

/**
 * Компонент скелетона для отображения состояния загрузки
 */
export const Skeleton: React.FC<SkeletonProps> = ({
  width,
  height,
  shape = 'rect',
  animated = true,
  animationSpeed = 1.5,
  count = 1,
  inline = false,
  gap = 8,
  direction = SkeletonGroupDirection.COLUMN,
  variant,
  borderRadius,
  ariaLabel,
  className,
  style,
}) => {
  // Валидация и нормализация пропсов
  const validatedProps = useMemo(
    () =>
      validateNumericProps({
        count,
        gap,
        animationSpeed,
      }),
    [count, gap, animationSpeed],
  );

  // Получаем размеры из варианта, если указан
  const variantDims = useMemo(() => getVariantDimensions(variant), [variant]);

  // Вычисляем финальные размеры
  const finalWidth = useMemo(
    () => getSizeValue(width || variantDims.width, variant ? undefined : '100%'),
    [width, variantDims.width, variant],
  );

  const finalHeight = useMemo(
    () => getSizeValue(height || variantDims.height, variant ? undefined : '16px'),
    [height, variantDims.height, variant],
  );

  const finalShape = useMemo(() => variantDims.shape || shape, [variantDims.shape, shape]);

  // Вычисляем border-radius
  const finalBorderRadius = useMemo(() => {
    if (borderRadius !== undefined) {
      return getSizeValue(borderRadius);
    }
    return finalShape === 'circle' ? '999px' : '12px';
  }, [borderRadius, finalShape]);

  // ARIA-атрибуты для доступности
  const ariaAttributes = useMemo(
    () => ({
      role: 'status' as const,
      'aria-label': ariaLabel || 'Загрузка контента',
      'aria-busy': animated,
    }),
    [ariaLabel, animated],
  );

  const groupItems = useMemo(
    (): React.ReactElement[] =>
      Array.from({ length: validatedProps.count }, (_, index) => (
        <SkeletonWrapper
          key={`skeleton-${index}`}
          $width={finalWidth}
          $height={finalHeight}
          $shape={finalShape}
          $animated={animated}
          $animationSpeed={validatedProps.animationSpeed}
          $borderRadius={finalBorderRadius}
          $inline={inline}
        />
      )),
    [
      validatedProps.count,
      finalWidth,
      finalHeight,
      finalShape,
      animated,
      validatedProps.animationSpeed,
      finalBorderRadius,
      inline,
    ],
  );

  // Рендерим один элемент
  if (validatedProps.count <= 1) {
    return (
      <SkeletonWrapper
        className={className}
        style={style}
        $width={finalWidth}
        $height={finalHeight}
        $shape={finalShape}
        $animated={animated}
        $animationSpeed={validatedProps.animationSpeed}
        $borderRadius={finalBorderRadius}
        $inline={inline}
        {...ariaAttributes}
      />
    );
  }

  return (
    <SkeletonGroup
      className={className}
      style={style}
      $gap={validatedProps.gap}
      $direction={direction}
      {...ariaAttributes}
    >
      {groupItems}
    </SkeletonGroup>
  );
};

Skeleton.displayName = 'Skeleton';

import React, { forwardRef, useMemo } from 'react';
import {
  SpinnerContainer,
  SpinnerWrapper,
  SpinnerLabel,
  SpinnerDots,
  SpinnerBars,
} from './Spinner.style';
import { clsx } from 'clsx';
import type { SpinnerProps } from '../../../types/ui';
import { SpinnerVariant } from '../../../types/ui';

/** Нормализованные числовые параметры анимации спиннера */
interface SpinnerMotionProps {
  speed: number;
  thickness: number;
}

/**
 * Валидирует скорость и толщину линии спиннера
 * @param props — частичные пропсы со `speed` и `thickness`
 */
const validateMotionProps = (
  props: Pick<SpinnerProps, 'speed' | 'thickness'>,
): SpinnerMotionProps => {
  const speed = props.speed ?? 1;
  const thickness = props.thickness ?? 2;

  return {
    speed: Math.max(0.1, Math.min(5, speed)),
    thickness: Math.max(1, Math.min(10, thickness)),
  };
};

/**
 * Компонент спиннера для отображения состояния загрузки
 */
export const Spinner = forwardRef<HTMLDivElement, SpinnerProps>(
  (
    {
      size,
      color = '#68d5f8',
      variant = SpinnerVariant.CIRCLE,
      speed = 1,
      thickness = 2,
      label,
      labelPosition = 'bottom',
      centered = false,
      ariaLabel,
      className,
      style,
    },
    ref,
  ) => {
    // Валидация и нормализация пропсов
    const validatedProps = useMemo(
      () =>
        validateMotionProps({
          speed,
          thickness,
        }),
      [speed, thickness],
    );

    // ARIA-атрибуты: `aria-label` только строка (`label` может быть `ReactNode`)
    const ariaAttributes = useMemo(() => {
      const labelForAria =
        typeof label === 'string' || typeof label === 'number' ? String(label) : undefined;
      return {
        role: 'status' as const,
        'aria-label': ariaLabel ?? labelForAria ?? 'Загрузка',
        'aria-busy': true as const,
      };
    }, [ariaLabel, label]);

    // Рендерим спиннер в зависимости от варианта
    const renderSpinner = () => {
      switch (variant) {
        case SpinnerVariant.DOTS:
          return (
            <SpinnerDots
              $size={size}
              $color={color}
              $speed={validatedProps.speed}
              $thickness={validatedProps.thickness}
              className={clsx('ui-spinner', className)}
              style={style}
              {...ariaAttributes}
              ref={ref}
            >
              <span />
              <span />
              <span />
            </SpinnerDots>
          );

        case SpinnerVariant.BARS:
          return (
            <SpinnerBars
              $size={size}
              $color={color}
              $speed={validatedProps.speed}
              $thickness={validatedProps.thickness}
              className={clsx('ui-spinner', className)}
              style={style}
              {...ariaAttributes}
              ref={ref}
            >
              <span />
              <span />
              <span />
            </SpinnerBars>
          );

        default:
          return (
            <SpinnerContainer
              $variant={variant}
              $size={size}
              $color={color}
              $speed={validatedProps.speed}
              $thickness={validatedProps.thickness}
              className={clsx('ui-spinner', className)}
              style={style}
              {...ariaAttributes}
              ref={
                variant === SpinnerVariant.CIRCLE || variant === SpinnerVariant.PULSE
                  ? ref
                  : undefined
              }
            />
          );
      }
    };

    const spinner = renderSpinner();

    // Если есть label, оборачиваем в контейнер
    if (label) {
      return (
        <SpinnerWrapper
          $centered={centered}
          $labelPosition={labelPosition}
          className={clsx('ui-spinner-wrapper', className)}
        >
          {labelPosition === 'top' && (
            <SpinnerLabel $position={labelPosition}>{label}</SpinnerLabel>
          )}
          {labelPosition === 'left' && (
            <SpinnerLabel $position={labelPosition}>{label}</SpinnerLabel>
          )}
          {spinner}
          {labelPosition === 'right' && (
            <SpinnerLabel $position={labelPosition}>{label}</SpinnerLabel>
          )}
          {labelPosition === 'bottom' && (
            <SpinnerLabel $position={labelPosition}>{label}</SpinnerLabel>
          )}
        </SpinnerWrapper>
      );
    }

    // Если нужно центрировать, оборачиваем в контейнер
    if (centered) {
      return (
        <SpinnerWrapper $centered={centered} className={clsx('ui-spinner-wrapper', className)}>
          {spinner}
        </SpinnerWrapper>
      );
    }

    return spinner;
  },
);

Spinner.displayName = 'Spinner';

