import React from 'react';
import { fireEvent, render, screen } from '@testing-library/react';
import { ThemeProvider } from '../../../themes/ThemeProvider';
import type { TabsSegmentOption } from '@/types/ui';
import { TabsDirection } from '@/types/ui';
import { Tabs } from './Tabs';

const renderWithTheme = (element: React.ReactElement) =>
  render(<ThemeProvider>{element}</ThemeProvider>);

function tabsSegmentTrackFromOptions(optionRows: TabsSegmentOption[]): React.ReactElement {
  return (
    <>
      {optionRows.map((row) => (
        <Tabs.Item key={row.value} {...row} />
      ))}
    </>
  );
}

describe('Tabs (сегменты без панелей)', () => {
  const demoOptions: TabsSegmentOption[] = [
    { value: 'a', label: 'Первый' },
    { value: 'b', label: 'Второй' },
  ];

  it('рендерит сегменты и группу с aria-label', () => {
    renderWithTheme(
      <Tabs ariaLabel="Тест переключателя" defaultValue="a">
        {tabsSegmentTrackFromOptions(demoOptions)}
      </Tabs>,
    );
    expect(screen.getByRole('group', { name: 'Тест переключателя' })).toBeInTheDocument();
    expect(screen.getByRole('button', { name: 'Первый' })).toHaveAttribute('aria-pressed', 'true');
    expect(screen.getByRole('button', { name: 'Второй' })).toHaveAttribute('aria-pressed', 'false');
  });

  it('переключает выбор в неконтролируемом режиме', () => {
    renderWithTheme(<Tabs defaultValue="a">{tabsSegmentTrackFromOptions(demoOptions)}</Tabs>);
    const secondButton = screen.getByRole('button', { name: 'Второй' });
    fireEvent.click(secondButton);
    expect(screen.getByRole('button', { name: 'Первый' })).toHaveAttribute('aria-pressed', 'false');
    expect(secondButton).toHaveAttribute('aria-pressed', 'true');
  });

  it('вызывает onChange в контролируемом режиме', () => {
    const handleChange = jest.fn();
    renderWithTheme(
      <Tabs value="a" onChange={handleChange} ariaLabel="Тип">
        {tabsSegmentTrackFromOptions(demoOptions)}
      </Tabs>,
    );
    fireEvent.click(screen.getByRole('button', { name: 'Второй' }));
    expect(handleChange).toHaveBeenCalledWith('b');
  });

  it('не переключает отключённый сегмент', () => {
    const handleChange = jest.fn();
    renderWithTheme(
      <Tabs defaultValue="x" onChange={handleChange}>
        <Tabs.Item value="x" label="Доступно" />
        <Tabs.Item value="y" label="Заблокировано" disabled />
      </Tabs>,
    );
    fireEvent.click(screen.getByRole('button', { name: 'Заблокировано' }));
    expect(handleChange).not.toHaveBeenCalled();
    expect(screen.getByRole('button', { name: 'Доступно' })).toHaveAttribute(
      'aria-pressed',
      'true',
    );
  });

  it('поддерживает вертикальное направление без ошибки', () => {
    renderWithTheme(
      <Tabs defaultValue="b" direction={TabsDirection.VERTICAL} ariaLabel="Вертикально">
        {tabsSegmentTrackFromOptions(demoOptions)}
      </Tabs>,
    );
    expect(screen.getByRole('group', { name: 'Вертикально' })).toBeInTheDocument();
  });
});

import { createContext, useContext } from 'react';

/** Регистрация узла сегмента на треке для расчёта позиции анимированного индикатора (**pill** или текстовые **minimal** / **line** / **underline**) */
export interface PillSegmentRegistrationContextValue {
  /** Учитывается только при активном pill-треке; иначе без эффекта */
  registerSegmentTriggerRef: (segmentValue: string, element: HTMLElement | null) => void;
}

const noopRegisterSegmentTriggerRef = (_segmentValue: string, _element: HTMLElement | null) => {};

const defaultPillSegmentRegistrationValue: PillSegmentRegistrationContextValue = {
  registerSegmentTriggerRef: noopRegisterSegmentTriggerRef,
};

export const PillSegmentRegistrationContext = createContext<PillSegmentRegistrationContextValue>(
  defaultPillSegmentRegistrationValue,
);

/**
 * Регистрация триггера сегмента (внутри TabItemGroupList в режиме pill).
 * Вне трека возвращает безопасную заглушку.
 */
export function usePillSegmentRegistration(): PillSegmentRegistrationContextValue {
  return useContext(PillSegmentRegistrationContext);
}

import styled, { css } from 'styled-components';
import { createStyledShouldForwardProp } from '../../../handlers/styledComponentHandlers';
import { TransitionHandler } from '../../../handlers/uiHandlers';
import { buildHoverPressMotionCss } from '../../../handlers/uiMotionStyleHandlers';
import type { Colors } from '../../../types/theme';
import type {
  TagAppearance,
  TagColorVariant,
  TagCustomColors,
  TagStatusDisplay,
} from '../../../types/ui';
import { ThemeMode } from '../../../types/theme';

type TagRootProps = {
  $color: TagColorVariant;
  $appearance: TagAppearance;
  $statusDisplay: TagStatusDisplay;
  $clickable: boolean;
  $disabled?: boolean;
  $padding: string;
  $gap: string;
  $fontSize: string;
  $minHeight: string;
  $widthCss?: string;
  $maxWidthCss?: string;
  $hideBorder?: boolean;
  /** Полная кастомизация заливки пилюли (есть `background`) */
  $customSurface?: TagCustomColors | null;
};

/** Сплошная заливка кружка статуса (режим `marker`) */
export const markerDotFill = (
  theme: { colors: Colors; mode?: ThemeMode },
  color: TagColorVariant,
): string => {
  switch (color) {
    case 'neutral':
      return theme.colors.borderTertiary;
    case 'primary':
      return theme.colors.tagPrimaryAccent;
    case 'info':
      return theme.colors.info;
    case 'danger':
      return theme.colors.danger;
    case 'success':
      return theme.colors.success;
    case 'warning':
      return theme.colors.warning;
    case 'secondary':
      return theme.colors.secondary;
    case 'purple':
      return theme.colors.tagAccentPurple;
    case 'teal':
      return theme.colors.tagAccentTeal;
    case 'cyan':
      return theme.colors.tagAccentCyan;
    case 'pink':
      return theme.colors.tagAccentPink;
    case 'custom':
      return theme.colors.borderTertiary;
    default:
      return theme.colors.borderTertiary;
  }
};

/** Тон заливки/обводки тега по варианту из темы */
type TagTone = {
  fg: string;
  border: string;
  fill: string;
  outlineBg: string;
  outlineBorder: string;
};

const getTagTone = (
  theme: { colors: Colors; mode?: ThemeMode },
  color: TagColorVariant,
  isDark: boolean,
): TagTone => {
  const mix = (accent: string, lightPct: number, darkPct: number) =>
    `color-mix(in srgb, ${accent} ${isDark ? darkPct : lightPct}%, ${theme.colors.input})`;

  switch (color) {
    case 'neutral':
      return {
        fg: theme.colors.textSecondary,
        border: theme.colors.borderSecondary,
        fill: isDark
          ? `color-mix(in srgb, ${theme.colors.textTertiary} 22%, ${theme.colors.input})`
          : `color-mix(in srgb, ${theme.colors.textTertiary} 12%, ${theme.colors.input})`,
        outlineBg: theme.colors.input,
        outlineBorder: theme.colors.borderTertiary,
      };
    case 'secondary':
      return {
        fg: theme.colors.secondary,
        border: theme.colors.secondary,
        fill: mix(theme.colors.secondary, 10, 18),
        outlineBg: theme.colors.input,
        outlineBorder: theme.colors.secondary,
      };
    case 'primary':
      return {
        fg: theme.colors.tagPrimaryAccent,
        border: theme.colors.tagPrimaryAccent,
        fill: mix(theme.colors.tagPrimaryAccent, 12, 22),
        outlineBg: theme.colors.input,
        outlineBorder: theme.colors.tagPrimaryAccent,
      };
    case 'danger':
      return {
        fg: theme.colors.danger,
        border: theme.colors.danger,
        fill: mix(theme.colors.danger, 14, 22),
        outlineBg: theme.colors.input,
        outlineBorder: theme.colors.danger,
      };
    case 'info':
      return {
        fg: theme.colors.info,
        border: theme.colors.info,
        fill: mix(theme.colors.info, 12, 22),
        outlineBg: theme.colors.input,
        outlineBorder: theme.colors.info,
      };
    case 'success':
      return {
        fg: theme.colors.success,
        border: theme.colors.success,
        fill: mix(theme.colors.success, 14, 22),
        outlineBg: theme.colors.input,
        outlineBorder: theme.colors.success,
      };
    case 'warning':
      return {
        fg: theme.colors.warning,
        border: theme.colors.warning,
        fill: mix(theme.colors.warning, 16, 24),
        outlineBg: theme.colors.input,
        outlineBorder: theme.colors.warning,
      };
    case 'purple':
      return {
        fg: theme.colors.tagAccentPurple,
        border: theme.colors.tagAccentPurple,
        fill: mix(theme.colors.tagAccentPurple, 14, 22),
        outlineBg: theme.colors.input,
        outlineBorder: theme.colors.tagAccentPurple,
      };
    case 'teal':
      return {
        fg: theme.colors.tagAccentTeal,
        border: theme.colors.tagAccentTeal,
        fill: mix(theme.colors.tagAccentTeal, 14, 22),
        outlineBg: theme.colors.input,
        outlineBorder: theme.colors.tagAccentTeal,
      };
    case 'cyan':
      return {
        fg: theme.colors.tagAccentCyan,
        border: theme.colors.tagAccentCyan,
        fill: mix(theme.colors.tagAccentCyan, 14, 22),
        outlineBg: theme.colors.input,
        outlineBorder: theme.colors.tagAccentCyan,
      };
    case 'pink':
      return {
        fg: theme.colors.tagAccentPink,
        border: theme.colors.tagAccentPink,
        fill: mix(theme.colors.tagAccentPink, 14, 22),
        outlineBg: theme.colors.input,
        outlineBorder: theme.colors.tagAccentPink,
      };
    case 'custom':
      return getTagTone(theme, 'neutral', isDark);
    default:
      return getTagTone(theme, 'neutral', isDark);
  }
};

const palette = (
  theme: { colors: Colors; mode?: ThemeMode },
  color: TagColorVariant,
  appearance: TagAppearance,
) => {
  const isDark = theme.mode === ThemeMode.DARK;
  const filled = appearance === 'filled';

  const tone = getTagTone(theme, color, isDark);

  if (filled) {
    return css`
      color: ${tone.fg};
      border: 1px solid ${tone.border};
      background: ${tone.fill};
    `;
  }
  return css`
    color: ${tone.fg};
    border: 1px solid ${tone.outlineBorder};
    background: ${tone.outlineBg};
  `;
};

const customSurfaceCss = (
  custom: NonNullable<TagRootProps['$customSurface']>,
  clickable: boolean,
  disabled?: boolean,
) => css`
  color: ${custom.color ?? 'inherit'};
  background: ${custom.background ?? 'transparent'};
  border: 1px solid ${custom.border ?? 'transparent'};
  ${clickable &&
  !disabled &&
  css`
    &:hover {
      filter: none;
      background: ${custom.backgroundHover ?? custom.background};
    }
    &:active {
      filter: brightness(0.96);
    }
  `}
`;

/**
 * Корневой элемент тега (полиморфный: `span` | `button` | `div`).
 * @property $statusDisplay - surface: палитра на всём теге; marker: нейтральная «пилюля» + цветной кружок
 * @property $customSurface — переопределение фона (не сочетается с marker в типах; в стилях игнорируем marker если передан custom)
 */
export const TagRoot = styled.span.withConfig({
  shouldForwardProp: createStyledShouldForwardProp(),
})<TagRootProps>`
  display: inline-flex;
  flex-direction: row;
  align-items: center;
  justify-content: center;
  box-sizing: border-box;
  gap: ${({ $gap }) => $gap};
  padding: ${({ $padding }) => $padding};
  min-height: ${({ $minHeight }) => $minHeight};
  border-radius: 6px;
  font-family: ${({ theme }) => theme.typography.caption.fontFamily};
  font-size: ${({ $fontSize }) => $fontSize};
  font-weight: ${({ theme }) => theme.typography.label.fontWeight};
  line-height: 1.25;
  white-space: nowrap;
  user-select: none;
  transition: ${TransitionHandler()};
  cursor: ${({ $clickable, $disabled }) =>
    $disabled ? 'not-allowed' : $clickable ? 'pointer' : 'default'};
  opacity: ${({ $disabled }) => ($disabled ? 0.55 : 1)};

  ${({ $widthCss }) => $widthCss && `width: ${$widthCss};`}
  ${({ $maxWidthCss }) => $maxWidthCss && `max-width: ${$maxWidthCss};`}

  ${({ $hideBorder }) =>
    $hideBorder &&
    css`
      border-color: transparent !important;
    `}

  ${({ $customSurface, $clickable, $disabled }) =>
    $customSurface?.background != null && `${$customSurface.background}`.length > 0
      ? customSurfaceCss($customSurface, Boolean($clickable), $disabled)
      : ''}

  ${({ theme, $color, $appearance, $statusDisplay, $customSurface }) =>
    !($customSurface?.background != null && `${$customSurface.background}`.length > 0) &&
    ($statusDisplay === 'marker'
      ? palette(theme, 'neutral', $appearance)
      : palette(theme, $color, $appearance))}

  ${({ $clickable, $disabled, theme, $customSurface }) =>
    $clickable &&
    !$disabled &&
    !($customSurface?.background != null && `${$customSurface.background}`.length > 0) &&
    css`
      &:hover {
        filter: brightness(0.97);
      }

      &:active {
        filter: brightness(0.93);
      }
      ${buildHoverPressMotionCss({
        hoverSelector: '&:hover',
        activeSelector: '&:active',
        hoverTransform: 'translateY(-1px)',
        activeTransform: 'scale(0.98)',
      })}

      &:focus-visible {
        outline: 2px solid ${theme.colors.primary};
        outline-offset: 2px;
      }
    `}

  ${({ $clickable, $disabled, theme, $customSurface }) =>
    $clickable &&
    !$disabled &&
    $customSurface?.background != null &&
    `${$customSurface.background}`.length > 0 &&
    css`
      &:hover {
      }
      ${buildHoverPressMotionCss({
        hoverSelector: '&:hover',
        activeSelector: '&:active',
        hoverTransform: 'translateY(-1px)',
        activeTransform: 'scale(0.98)',
      })}

      &:focus-visible {
        outline: 2px solid ${theme.colors.primary};
        outline-offset: 2px;
      }
    `}
`;

/** Цветная метка статуса слева (режим `statusDisplay="marker"`) */
export const TagStatusMarker = styled.span.withConfig({
  shouldForwardProp: createStyledShouldForwardProp(),
})<{ $markerColor: TagColorVariant; $markerFill?: string }>`
  flex-shrink: 0;
  width: 8px;
  height: 8px;
  border-radius: 50%;
  margin-right: 6px;
  background: ${({ theme, $markerColor, $markerFill }) =>
    $markerFill ?? markerDotFill(theme, $markerColor)};
`;

/** Обёртка иконки (выравнивание с текстом) */
export const TagIconSlot = styled.span`
  display: inline-flex;
  flex-shrink: 0;
  align-items: center;
  justify-content: center;
  line-height: 0;
`;

/** Текстовая часть */
export const TagLabel = styled.span<{ $ellipsis?: boolean }>`
  min-width: 0;
  ${({ $ellipsis }) =>
    $ellipsis &&
    css`
      overflow: hidden;
      text-overflow: ellipsis;
    `}
`;

import React, { forwardRef, useCallback, useLayoutEffect, useMemo, useRef, useState } from 'react';
import { clsx } from 'clsx';
import type { TagColorVariant, TagProps } from '../../../types/ui';
import { Size } from '../../../types/sizes';
import { Tooltip } from '../Tooltip/Tooltip';
import { TooltipPosition } from '../../../types/ui';
import { TagRoot, TagIconSlot, TagLabel, TagStatusMarker } from './Tag.style';
import { TagSkeletonRoot } from './TagSkeleton.style';
import { getTagMetrics, getTagSkeletonDefaultWidthPx, tagLengthToCss } from './handlers';

/**
 * Тег из макета Figma: палитра темы, режимы **surface** / **marker**, кастомные цвета.
 * палитра × filled/outline, режим **surface** / **marker** (цветной кружок), кастомные цвета поверхности,
 * ширина, тултип при переполнении, полиморфный корень (`as="button"`).
 *
 * @param props.children - Текст
 * @param props.colorVariant — Цветовая схема (`primary` — основной акцент темы)
 * @param props.appearance - Заливка или обводка
 * @param props.statusDisplay - `surface` — красим всю пилюлю; `marker` — нейтральный фон и цветной маркер слева
 * @param props.size - Размер (по умолчанию SM)
 * @param props.leftIcon / rightIcon - Слоты под иконки
 * @param props.onClick - Кликабельность; при `as="button"` — нативная кнопка
 * @param props.disabled - Блокировка
 * @param props.skeleton / skeletonWidth - Плейсхолдер загрузки
 * @param props.width / maxWidth - Габариты
 * @param props.as - `span` | `button` | `div`
 * @param props.customColors — Фон/бордер/hover/текст (`background` включает полностью кастомную пилюлю); `marker` — цвет кружка в режиме `statusDisplay="marker"`
 * @param props.hideBorder - Скрыть обводку
 * @param props.tooltipWhenTruncated / tooltipContent - Тултип при ellipsis
 * @param ref - Ref на корневой элемент
 */
export const Tag = forwardRef<HTMLElement, TagProps>(
  (
    {
      children,
      colorVariant = 'neutral',
      appearance = 'filled',
      statusDisplay: statusDisplayProp = 'surface',
      size = Size.SM,
      leftIcon,
      rightIcon,
      onClick,
      disabled = false,
      skeleton = false,
      skeletonWidth,
      width,
      maxWidth,
      as: rootElement = 'span',
      customColors,
      hideBorder = false,
      tooltipWhenTruncated = false,
      tooltipContent,
      className,
      role: roleProp,
      tabIndex: tabIndexProp,
      onKeyDown: onKeyDownProp,
      ...rest
    },
    ref,
  ) => {
    const metrics = useMemo(() => getTagMetrics(size), [size]);

    /** Полная кастомная заливка пилюли — только при заданном `background` */
    const hasFullCustomChip = Boolean(customColors?.background);
    const statusDisplay = hasFullCustomChip ? 'surface' : statusDisplayProp;
    /** Для палитры темы: `custom` без своих цветов трактуем как нейтральный */
    const paletteColorVariant: TagColorVariant =
      colorVariant === 'custom' && !hasFullCustomChip ? 'neutral' : colorVariant;

    const widthCss = tagLengthToCss(width);
    const maxWidthCss = tagLengthToCss(maxWidth);
    const labelRef = useRef<HTMLSpanElement>(null);
    const [isTextTruncated, setIsTextTruncated] = useState(false);

    useLayoutEffect(() => {
      const element = labelRef.current;
      if (!element || !tooltipWhenTruncated) {
        setIsTextTruncated(false);
        return;
      }
      setIsTextTruncated(element.scrollWidth > element.clientWidth);
    }, [children, tooltipWhenTruncated, maxWidth, width, metrics.fontSize]);

    const useNativeButton = rootElement === 'button';
    const clickable = Boolean(onClick) && !disabled;
    const showMarker = statusDisplay === 'marker';

    const role = roleProp ?? (clickable && !useNativeButton ? 'button' : undefined);
    const tabIndex = tabIndexProp ?? (clickable && !useNativeButton ? 0 : undefined);

    const handleKeyDown = useCallback(
      (keyboardEvent: React.KeyboardEvent<HTMLElement>) => {
        onKeyDownProp?.(keyboardEvent as React.KeyboardEvent<HTMLSpanElement>);
        if (keyboardEvent.defaultPrevented || !clickable || !onClick || useNativeButton) {
          return;
        }
        if (keyboardEvent.key === 'Enter' || keyboardEvent.key === ' ') {
          keyboardEvent.preventDefault();
          (keyboardEvent.currentTarget as HTMLElement).click();
        }
      },
      [clickable, onClick, onKeyDownProp, useNativeButton],
    );

    const handleClick = useCallback(
      (mouseEvent: React.MouseEvent<HTMLElement>) => {
        if (disabled) {
          mouseEvent.preventDefault();
          return;
        }
        onClick?.(mouseEvent as React.MouseEvent<HTMLSpanElement>);
      },
      [disabled, onClick],
    );

    if (skeleton) {
      const widthPx = skeletonWidth ?? getTagSkeletonDefaultWidthPx(size);
      return (
        <TagSkeletonRoot
          ref={ref as React.Ref<HTMLSpanElement>}
          {...rest}
          className={clsx('ui-tag', 'ui-tag--skeleton', className)}
          aria-busy="true"
          $minHeight={metrics.minHeight}
          $widthPx={widthPx}
        />
      );
    }

    const ellipsisActive = Boolean(widthCss ?? maxWidthCss);

    const tagInner = (
      <TagRoot
        ref={ref}
        {...rest}
        as={rootElement}
        {...(useNativeButton ? { type: 'button' as const, disabled } : {})}
        role={role}
        tabIndex={tabIndex}
        onClick={onClick ? handleClick : undefined}
        onKeyDown={clickable && !useNativeButton ? handleKeyDown : onKeyDownProp}
        aria-disabled={useNativeButton ? undefined : disabled || undefined}
        $color={paletteColorVariant}
        $appearance={appearance}
        $statusDisplay={statusDisplay}
        $clickable={clickable}
        $disabled={disabled}
        $padding={metrics.padding}
        $gap={metrics.gap}
        $fontSize={metrics.fontSize}
        $minHeight={metrics.minHeight}
        $widthCss={widthCss}
        $maxWidthCss={maxWidthCss}
        $hideBorder={hideBorder}
        $customSurface={customColors ?? null}
        className={clsx('ui-tag', className)}
      >
        {showMarker ? (
          <TagStatusMarker
            $markerColor={paletteColorVariant}
            $markerFill={customColors?.marker}
            aria-hidden
          />
        ) : null}
        {leftIcon ? <TagIconSlot aria-hidden>{leftIcon}</TagIconSlot> : null}
        {children ? (
          <TagLabel ref={labelRef} $ellipsis={ellipsisActive}>
            {children}
          </TagLabel>
        ) : null}
        {rightIcon ? <TagIconSlot aria-hidden>{rightIcon}</TagIconSlot> : null}
      </TagRoot>
    );

    const tooltipBody: React.ReactNode =
      tooltipContent ??
      (typeof children === 'string' || typeof children === 'number' ? children : null);
    const hasTooltipPayload =
      tooltipBody != null && (typeof tooltipBody !== 'string' || tooltipBody.length > 0);
    const showTruncationTooltip = tooltipWhenTruncated && isTextTruncated && hasTooltipPayload;

    if (!tooltipWhenTruncated) {
      return tagInner;
    }

    return (
      <Tooltip
        content={tooltipBody ?? ''}
        position={TooltipPosition.TOP}
        disabled={!showTruncationTooltip}
      >
        {tagInner}
      </Tooltip>
    );
  },
);

Tag.displayName = 'Tag';

import React, { useState, useRef, useEffect, useCallback, forwardRef } from 'react';
import { createPortal } from 'react-dom';
import { clsx } from 'clsx';
import type { TooltipProps } from '../../../types/ui';
import { TooltipPosition } from '../../../types/ui';
import { Size } from '../../../types/sizes';
import { TooltipContent, TooltipTrigger } from './Tooltip.style';

export interface TooltipState {
  isVisible: boolean;
  position: { x: number; y: number };
  placement: TooltipPosition;
}

interface TooltipBounds {
  left: number;
  right: number;
  top: number;
  bottom: number;
}

export const Tooltip: React.FC<TooltipProps> = forwardRef<HTMLDivElement, TooltipProps>(
  (
    {
      children,
      content,
      position = TooltipPosition.TOP,
      size = Size.MD,
      className,
      delay = 200,
      disabled = false,
    },
    _ref,
  ) => {
    const [tooltipState, setTooltipState] = useState<TooltipState>({
      isVisible: false,
      position: { x: 0, y: 0 },
      placement: position,
    });

    const triggerRef = useRef<HTMLDivElement>(null);
    const tooltipRef = useRef<HTMLDivElement>(null);
    const timeoutRef = useRef<NodeJS.Timeout>();

    const viewportPadding = 8;
    const tooltipOffset = 8;

    const getPositionForPlacement = useCallback(
      (triggerRect: DOMRect, placement: TooltipPosition): { x: number; y: number } => {
        if (placement === TooltipPosition.TOP) {
          return {
            x: triggerRect.left + triggerRect.width / 2,
            y: triggerRect.top - tooltipOffset,
          };
        }
        if (placement === TooltipPosition.BOTTOM) {
          return {
            x: triggerRect.left + triggerRect.width / 2,
            y: triggerRect.bottom + tooltipOffset,
          };
        }
        if (placement === TooltipPosition.LEFT) {
          return {
            x: triggerRect.left - tooltipOffset,
            y: triggerRect.top + triggerRect.height / 2,
          };
        }

        return {
          x: triggerRect.right + tooltipOffset,
          y: triggerRect.top + triggerRect.height / 2,
        };
      },
      [],
    );

    const getTooltipBounds = useCallback(
      (
        tooltipPosition: { x: number; y: number },
        placement: TooltipPosition,
        tooltipSize: { width: number; height: number },
      ): TooltipBounds => {
        if (placement === TooltipPosition.TOP) {
          return {
            left: tooltipPosition.x - tooltipSize.width / 2,
            right: tooltipPosition.x + tooltipSize.width / 2,
            top: tooltipPosition.y - tooltipSize.height,
            bottom: tooltipPosition.y,
          };
        }
        if (placement === TooltipPosition.BOTTOM) {
          return {
            left: tooltipPosition.x - tooltipSize.width / 2,
            right: tooltipPosition.x + tooltipSize.width / 2,
            top: tooltipPosition.y,
            bottom: tooltipPosition.y + tooltipSize.height,
          };
        }
        if (placement === TooltipPosition.LEFT) {
          return {
            left: tooltipPosition.x - tooltipSize.width,
            right: tooltipPosition.x,
            top: tooltipPosition.y - tooltipSize.height / 2,
            bottom: tooltipPosition.y + tooltipSize.height / 2,
          };
        }

        return {
          left: tooltipPosition.x,
          right: tooltipPosition.x + tooltipSize.width,
          top: tooltipPosition.y - tooltipSize.height / 2,
          bottom: tooltipPosition.y + tooltipSize.height / 2,
        };
      },
      [],
    );

    const clampPositionToViewport = useCallback(
      (
        tooltipPosition: { x: number; y: number },
        placement: TooltipPosition,
        tooltipSize: { width: number; height: number },
      ): { x: number; y: number } => {
        const viewportWidth = window.innerWidth;
        const viewportHeight = window.innerHeight;
        const bounds = getTooltipBounds(tooltipPosition, placement, tooltipSize);

        if (bounds.left < viewportPadding) {
          tooltipPosition.x += viewportPadding - bounds.left;
        }
        if (bounds.right > viewportWidth - viewportPadding) {
          tooltipPosition.x -= bounds.right - (viewportWidth - viewportPadding);
        }
        if (bounds.top < viewportPadding) {
          tooltipPosition.y += viewportPadding - bounds.top;
        }
        if (bounds.bottom > viewportHeight - viewportPadding) {
          tooltipPosition.y -= bounds.bottom - (viewportHeight - viewportPadding);
        }

        return tooltipPosition;
      },
      [getTooltipBounds],
    );

    const resolveTooltipGeometry = useCallback(
      (preferredPlacement: TooltipPosition) => {
        if (!triggerRef.current) {
          return {
            placement: preferredPlacement,
            position: { x: 0, y: 0 },
          };
        }

        const triggerRect = triggerRef.current.getBoundingClientRect();
        const tooltipRect = tooltipRef.current?.getBoundingClientRect();
        const tooltipSize = {
          width: tooltipRect?.width ?? 220,
          height: tooltipRect?.height ?? 40,
        };
        const fallbackPlacementMap: Record<TooltipPosition, TooltipPosition> = {
          [TooltipPosition.TOP]: TooltipPosition.BOTTOM,
          [TooltipPosition.BOTTOM]: TooltipPosition.TOP,
          [TooltipPosition.LEFT]: TooltipPosition.RIGHT,
          [TooltipPosition.RIGHT]: TooltipPosition.LEFT,
        };

        const preferredPosition = getPositionForPlacement(triggerRect, preferredPlacement);
        const preferredBounds = getTooltipBounds(
          preferredPosition,
          preferredPlacement,
          tooltipSize,
        );
        const viewportWidth = window.innerWidth;
        const viewportHeight = window.innerHeight;
        const hasOverflowOnPrimaryAxis =
          (preferredPlacement === TooltipPosition.TOP && preferredBounds.top < viewportPadding) ||
          (preferredPlacement === TooltipPosition.BOTTOM &&
            preferredBounds.bottom > viewportHeight - viewportPadding) ||
          (preferredPlacement === TooltipPosition.LEFT && preferredBounds.left < viewportPadding) ||
          (preferredPlacement === TooltipPosition.RIGHT &&
            preferredBounds.right > viewportWidth - viewportPadding);

        const resolvedPlacement = hasOverflowOnPrimaryAxis
          ? fallbackPlacementMap[preferredPlacement]
          : preferredPlacement;
        const resolvedPosition = getPositionForPlacement(triggerRect, resolvedPlacement);

        return {
          placement: resolvedPlacement,
          position: clampPositionToViewport(resolvedPosition, resolvedPlacement, tooltipSize),
        };
      },
      [clampPositionToViewport, getPositionForPlacement, getTooltipBounds],
    );

    // Показать tooltip
    const showTooltip = useCallback(() => {
      if (disabled) return;

      timeoutRef.current = setTimeout(() => {
        const tooltipGeometry = resolveTooltipGeometry(position);
        setTooltipState({
          isVisible: true,
          position: tooltipGeometry.position,
          placement: tooltipGeometry.placement,
        });
      }, delay);
    }, [disabled, delay, position, resolveTooltipGeometry]);

    // Скрыть tooltip
    const hideTooltip = useCallback(() => {
      if (timeoutRef.current) {
        clearTimeout(timeoutRef.current);
      }
      setTooltipState((prev) => ({ ...prev, isVisible: false }));
    }, []);

    // Обработчики событий
    const handleMouseEnter = () => {
      showTooltip();
    };

    const handleMouseLeave = () => {
      hideTooltip();
    };

    const handleFocus = () => {
      showTooltip();
    };

    const handleBlur = () => {
      hideTooltip();
    };

    // Очистка при размонтировании
    useEffect(() => {
      return () => {
        if (timeoutRef.current) {
          clearTimeout(timeoutRef.current);
        }
      };
    }, []);

    // Обновляем позицию при изменении размера окна
    useEffect(() => {
      const updateTooltipPosition = () => {
        if (tooltipState.isVisible) {
          const tooltipGeometry = resolveTooltipGeometry(position);
          setTooltipState((prev) => ({
            ...prev,
            position: tooltipGeometry.position,
            placement: tooltipGeometry.placement,
          }));
        }
      };

      window.addEventListener('resize', updateTooltipPosition);
      window.addEventListener('scroll', updateTooltipPosition, true);
      return () => {
        window.removeEventListener('resize', updateTooltipPosition);
        window.removeEventListener('scroll', updateTooltipPosition, true);
      };
    }, [tooltipState.isVisible, position, resolveTooltipGeometry]);

    // После монтирования тултипа пересчитываем точные координаты по реальным размерам.
    useEffect(() => {
      if (!tooltipState.isVisible) {
        return;
      }

      const tooltipGeometry = resolveTooltipGeometry(position);
      setTooltipState((prev) => {
        if (
          prev.placement === tooltipGeometry.placement &&
          prev.position.x === tooltipGeometry.position.x &&
          prev.position.y === tooltipGeometry.position.y
        ) {
          return prev;
        }

        return {
          ...prev,
          position: tooltipGeometry.position,
          placement: tooltipGeometry.placement,
        };
      });
    }, [tooltipState.isVisible, position, resolveTooltipGeometry]);

    return (
      <>
        <TooltipTrigger
          ref={triggerRef}
          className={clsx('ui-tooltip-trigger', className)}
          onMouseEnter={handleMouseEnter}
          onMouseLeave={handleMouseLeave}
          onFocus={handleFocus}
          onBlur={handleBlur}
          tabIndex={disabled ? -1 : 0}
        >
          {children}
        </TooltipTrigger>

        {tooltipState.isVisible &&
          createPortal(
            <TooltipContent
              ref={tooltipRef}
              data-tooltip-content
              $position={tooltipState.position}
              $placement={tooltipState.placement}
              $isVisible={tooltipState.isVisible}
              $size={size}
            >
              {content}
            </TooltipContent>,
            document.body,
          )}
      </>
    );
  },
);

Tooltip.displayName = 'Tooltip';

import React, { forwardRef, useMemo, useState } from 'react';
import { clsx } from 'clsx';
import type { ButtonGroupProps } from '@/types/ui';
import { ButtonVariant } from '@/types/ui';
import { Size } from '@/types/sizes';
import { ButtonGroupRoot } from './ButtonGroup.style';

/**
 * Группа кнопок: общий `role="group"`, горизонталь или вертикаль, опционально склеенные границы (`attached`) по макету Figma.
 * @param props - Пропсы `ButtonGroupProps`.
 * @param ref - Ref на корневой `div`.
 */
export const ButtonGroup = forwardRef<HTMLDivElement, ButtonGroupProps>(
  (
    {
      children,
      orientation = 'horizontal',
      attached = false,
      size = Size.MD,
      attachedShape = 'segment',
      fullWidth = false,
      selectable = false,
      activeIndex,
      defaultActiveIndex = 0,
      onActiveIndexChange,
      activeButtonVariant = ButtonVariant.PRIMARY,
      inactiveButtonVariant = ButtonVariant.OUTLINE,
      role = 'group',
      ariaLabel,
      className,
    },
    ref,
  ) => {
    const [localActiveButtonIndex, setLocalActiveButtonIndex] = useState(defaultActiveIndex);
    const resolvedActiveButtonIndex =
      typeof activeIndex === 'number' ? activeIndex : localActiveButtonIndex;

    const preparedChildren = useMemo(() => {
      if (!selectable) {
        return children;
      }

      return React.Children.map(children, (childNode, childIndex) => {
        if (!React.isValidElement(childNode)) {
          return childNode;
        }

        const childProps = (childNode.props ?? {}) as {
          onClick?: (event: React.MouseEvent<HTMLElement>) => void;
          variant?: ButtonVariant;
        };
        const isActiveButton = childIndex === resolvedActiveButtonIndex;
        const variantForChild = isActiveButton ? activeButtonVariant : inactiveButtonVariant;

        return React.cloneElement(childNode, {
          ...childProps,
          variant: variantForChild,
          'data-active': isActiveButton ? 'true' : 'false',
          'aria-pressed': isActiveButton,
          onClick: (event: React.MouseEvent<HTMLElement>) => {
            childProps.onClick?.(event);
            if (typeof activeIndex !== 'number') {
              setLocalActiveButtonIndex(childIndex);
            }
            onActiveIndexChange?.(childIndex);
          },
        });
      });
    }, [
      selectable,
      children,
      resolvedActiveButtonIndex,
      activeButtonVariant,
      inactiveButtonVariant,
      activeIndex,
      onActiveIndexChange,
    ]);

    return (
      <ButtonGroupRoot
        ref={ref}
        className={clsx('ui-button-group', className)}
        role={role}
        aria-label={ariaLabel}
        $orientation={orientation}
        $attached={attached}
        $size={size}
        $attachedShape={attachedShape}
        $fullWidth={fullWidth}
      >
        {preparedChildren}
      </ButtonGroupRoot>
    );
  },
);

ButtonGroup.displayName = 'ButtonGroup';

import styled, { css } from 'styled-components';
import { motion } from 'framer-motion';
import type { IconButtonProps } from '../../../../types/ui';
import { ButtonVariant } from '../../../../types/ui';
import { Size } from '../../../../types/sizes';
import { getButtonSize } from '../../../../handlers/buttonThemeHandlers';
import { createStyledShouldForwardProp } from '../../../../handlers/styledComponentHandlers';

const iconButtonStyleConfig = {
  shouldForwardProp: createStyledShouldForwardProp([
    'variant',
    'size',
    'loading',
    'fullWidth',
    'rounded',
    'icon',
  ]),
};

/**
 * Стилизованная иконка-кнопка
 * @param variant - вариант кнопки (дублирует ButtonVariant)
 * @param size - размер кнопки
 * @param disabled - состояние отключения
 * @param loading - состояние загрузки
 * @param fullWidth - растянуть на всю ширину
 * @param rounded - скругленные углы
 */
export const StyledIconButton = styled(motion.button).withConfig(
  iconButtonStyleConfig,
)<IconButtonProps>`
  box-sizing: border-box;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  border: none;
  padding: 0;
  cursor: pointer;
  position: relative;
  overflow: hidden;
  font-family: inherit;
  font-weight: 500;
  text-decoration: none;
  outline: none;
  gap: 0;
  line-height: 0;

  /* Базовые стили (fallback) - только для не-skeleton вариантов */
  ${({ variant }) =>
    variant !== ButtonVariant.SKELETON &&
    css`
      background-color: #007bff;
      color: #ffffff;
      border: 1px solid #007bff;
    `}

  /* Размеры кнопки */
  ${({ size = Size.MD }) => {
    switch (size) {
      case Size.SM:
        return css`
          width: 32px;
          height: 32px;
          min-width: 32px;
          min-height: 32px;
          font-size: 12px;
        `;
      case Size.MD:
        return css`
          width: 40px;
          height: 40px;
          min-width: 40px;
          min-height: 40px;
          font-size: 14px;
        `;
      case Size.LG:
        return css`
          width: 48px;
          height: 48px;
          min-width: 48px;
          min-height: 48px;
          font-size: 16px;
        `;
      default:
        return css`
          width: 40px;
          height: 40px;
          min-width: 40px;
          min-height: 40px;
          font-size: 14px;
        `;
    }
  }}

  /* Форма кнопки */
  ${({ rounded, size = Size.MD, theme }) =>
    rounded
      ? css`
          border-radius: 50%;
        `
      : css`
          border-radius: ${getButtonSize(theme?.buttons, size).borderRadius};
        `}

  /* Растягивание на всю ширину */
  ${({ fullWidth }) =>
    fullWidth &&
    css`
      width: 100%;
    `}

  /* Стили вариантов кнопки */
  ${({ variant = ButtonVariant.PRIMARY, theme }) => {
    const variantStyles = theme?.buttons?.variants?.[variant];
    if (!variantStyles) return css``;

    // Специальная обработка для skeleton варианта
    if (variant === ButtonVariant.SKELETON) {
      return css`
        background-image: ${variantStyles.background ||
        'linear-gradient(90deg, #e5e7eb 25%, #f3f4f6 50%, #e5e7eb 75%)'};
        background-size: ${(variantStyles as { backgroundSize?: string }).backgroundSize ||
        '200% 100%'};
        background-position: ${(variantStyles as { backgroundPosition?: string })
          .backgroundPosition || '-200% 0'};
        background-repeat: no-repeat;
        animation: ${(variantStyles as { animation?: string }).animation ||
        'skeleton-loading 1.5s infinite ease-in-out'};
        color: ${variantStyles.color || '#9ca3af80'};
        border: ${variantStyles.border || '2px solid #d1d5db'};

        /* В skeleton-режиме оставляем прозрачность без blur, чтобы не было оптического смещения центра. */
        .ui-icon-button-content {
          opacity: 0.7;
        }

        &:hover:not(:disabled) {
          background-image: ${variantStyles.hover?.background ||
          'linear-gradient(90deg, #e5e7eb 25%, #f3f4f6 50%, #e5e7eb 75%)'};
          background-size: ${(variantStyles.hover as { backgroundSize?: string })?.backgroundSize ||
          '200% 100%'};
          background-position: ${(variantStyles.hover as { backgroundPosition?: string })
            ?.backgroundPosition || '-200% 0'};
          background-repeat: no-repeat;
          animation: ${(variantStyles.hover as { animation?: string })?.animation ||
          'skeleton-loading 1.5s infinite ease-in-out'};
          color: ${variantStyles.hover?.color || '#9ca3af80'};
          border: ${variantStyles.hover?.border || '2px solid #d1d5db'};

          .ui-icon-button-content {
            opacity: 0.7;
          }
        }

        &:active:not(:disabled) {
          background-image: ${variantStyles.active?.background ||
          'linear-gradient(90deg, #e5e7eb 25%, #f3f4f6 50%, #e5e7eb 75%)'};
          background-size: ${(variantStyles.active as { backgroundSize?: string })
            ?.backgroundSize || '200% 100%'};
          background-position: ${(variantStyles.active as { backgroundPosition?: string })
            ?.backgroundPosition || '-200% 0'};
          background-repeat: no-repeat;
          animation: ${(variantStyles.active as { animation?: string })?.animation ||
          'skeleton-loading 1.5s infinite ease-in-out'};
          color: ${variantStyles.active?.color || '#9ca3af80'};
          border: ${variantStyles.active?.border || '2px solid #d1d5db'};

          .ui-icon-button-content {
            opacity: 0.7;
          }
        }

        &:focus-visible {
          border: ${variantStyles.focus?.border || '2px solid #9ca3af'};
          outline: ${variantStyles.focus?.outline || 'none'};
        }

        &:disabled {
          background-image: ${variantStyles.disabled?.background ||
          'linear-gradient(90deg, #e5e7eb 25%, #f3f4f6 50%, #e5e7eb 75%)'};
          background-size: ${(variantStyles.disabled as { backgroundSize?: string })
            ?.backgroundSize || '200% 100%'};
          background-position: ${(variantStyles.disabled as { backgroundPosition?: string })
            ?.backgroundPosition || '-200% 0'};
          background-repeat: no-repeat;
          animation: ${(variantStyles.disabled as { animation?: string })?.animation ||
          'skeleton-loading 1.5s infinite ease-in-out'};
          color: ${variantStyles.disabled?.color || '#9ca3af80'};
          border: ${variantStyles.disabled?.border || '2px solid #d1d5db'};
          opacity: 0.6;
          cursor: not-allowed;

          .ui-icon-button-content {
            opacity: 0.7;
          }
        }
      `;
    }

    // Обычные стили для всех остальных вариантов
    return css`
      background-color: ${variantStyles.background};
      color: ${variantStyles.color};
      border: ${variantStyles.border};

      &:hover:not(:disabled) {
        background-color: ${variantStyles.hover.background};
        color: ${variantStyles.hover.color};
        border: ${variantStyles.hover.border};
      }

      &:active:not(:disabled) {
        background-color: ${variantStyles.active.background};
        color: ${variantStyles.active.color};
        border: ${variantStyles.active.border};
      }

      &:focus-visible {
        border: ${variantStyles.focus.border};
        outline: ${variantStyles.focus.outline || 'none'};
      }

      &:disabled {
        background-color: ${variantStyles.disabled.background};
        color: ${variantStyles.disabled.color};
        border: ${variantStyles.disabled.border};
        opacity: 0.6;
        cursor: not-allowed;
      }
    `;
  }}

  /* Состояние загрузки */
  ${({ loading }) =>
    loading &&
    css`
      cursor: wait;
      pointer-events: none;
    `}

  /* Анимации */
  transition: ${({ theme }) => theme?.buttons?.animations?.transition || 'all 0.2s ease-in-out'};
`;

