        ) : (
          <InputWrapper
            variant={variant}
            size={size}
            error={error}
            success={success}
            status={currentStatus}
            fullWidth={fullWidth}
            focused={focused}
            readOnly={readOnly}
            className={className}
          >
            {leftIcon && (
              <IconContainer $position="left" size={size}>
                {leftIcon}
              </IconContainer>
            )}

            <StyledInput
              ref={ref}
              id={inputId}
              type={type}
              value={displayValue}
              onChange={handleChange}
              onFocus={handleFocus}
              onBlur={handleBlur}
              placeholder={placeholder}
              disabled={disabled}
              readOnly={readOnly}
              required={required}
              textAlign={textAlign}
              onCopy={handleCopy}
              onPaste={handlePaste}
              form={formContext?.formId}
              autoComplete={getAutocompleteValue()}
              {...props}
            />

            {rightIcon && (
              <IconContainer $position="right" size={size}>
                {rightIcon}
              </IconContainer>
            )}

            {isLoading && <LoadingSpinner size={size} />}

            {showClearButton && (
              <ClearButton onClick={handleClear} type="button">
                <Icon
                  name="IconExClose"
                  size={getClearIconSizeForInputField(size)}
                  {...clearIconProps}
                />
              </ClearButton>
            )}
          </InputWrapper>
        )}

        {/* Вспомогательные тексты */}
        {error && <ErrorText>{error}</ErrorText>}
        {success && <SuccessText>Успешно</SuccessText>}
        {helperText && !error && !success && <HelperText>{helperText}</HelperText>}
        {extraText && <ExtraText>{extraText}</ExtraText>}

