/**
 * Ограничение высоты заголовка: `headerMaxLines` у `TableCell` + `maxLines` у `TableSortLabel`; для несортируемой ячейки — `TableCellHeadLineClamp`.
 */
export const HeadMaxLinesClamp: Story = {
  parameters: {
    docs: {
