import { useMemo } from 'react';
import type { CSSProperties } from 'react';
import { getModalMountNode } from '../components/ui/Modal/handlers';

type UseOverlayPortalParameters = {
  /**
   * Контейнер для портала. Если не задан, используется `portalTargetId`, далее `document.body`.
   */
  container?: Element | null;
  /**
   * ID контейнера для портала.
   */
  portalTargetId?: string;
  /**
   * Inline-стили оверлея.
   */
  overlayStyle?: CSSProperties;
  /**
   * Принудительный z-index, добавляемый поверх `overlayStyle`.
   */
  portalZIndex?: number;
};

type UseOverlayPortalResult = {
  /**
   * Узел, в который монтируется портал.
   */
  mountNode: Element | null;
  /**
   * Готовые inline-стили оверлея с учётом `portalZIndex`.
   */
  overlayInlineStyle: CSSProperties | undefined;
};

/**
 * Единая логика для порталов оверлейных компонентов.
 * @param overlayPortalParameters - параметры контейнера и стилей портала
 */
export const useOverlayPortal = (
  overlayPortalParameters: UseOverlayPortalParameters,
): UseOverlayPortalResult => {
  const { container, portalTargetId, overlayStyle, portalZIndex } = overlayPortalParameters;

  const mountNode = useMemo(
    () => getModalMountNode(container, portalTargetId),
    [container, portalTargetId],
  );

  const overlayInlineStyle = useMemo(() => {
    if (portalZIndex === undefined) {
      return overlayStyle;
    }

    return { ...(overlayStyle || {}), zIndex: portalZIndex };
  }, [overlayStyle, portalZIndex]);

  return { mountNode, overlayInlineStyle };
};

import { useMemo } from 'react';
import type { CSSProperties } from 'react';

type UseOverlayPresentationParameters = {
  /**
   * Текущее состояние открытия оверлейного компонента.
   */
  isOpen: boolean;
  /**
   * Скрывать ли компонент, сохраняя его в DOM.
   */
  isHidden: boolean;
  /**
   * Базовые inline-стили оверлея.
   */
  overlayInlineStyle?: CSSProperties;
};

type UseOverlayPresentationResult = {
  /**
   * Финальные inline-стили для оверлея.
   */
  overlayPresentationStyle: CSSProperties | undefined;
  /**
   * Признак скрытия для accessibility.
   */
  ariaHidden: boolean;
};

/**
 * Единая логика presentation-слоя оверлея:
 * рассчитывает `style` и `aria-hidden` для закрытого состояния.
 * @param overlayPresentationParameters - параметры отображения оверлея
 */
export const useOverlayPresentation = (
  overlayPresentationParameters: UseOverlayPresentationParameters,
): UseOverlayPresentationResult => {
  const { isOpen, isHidden, overlayInlineStyle } = overlayPresentationParameters;

  const overlayPresentationStyle = useMemo(() => {
    if (!isHidden) {
      return overlayInlineStyle;
    }

    return { ...(overlayInlineStyle || {}), display: 'none' as const };
  }, [isHidden, overlayInlineStyle]);

  return {
    overlayPresentationStyle,
    ariaHidden: !isOpen,
  };
};

